import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIAssistance = async (prompt: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "أنت معلم قرآن خبير في منصة آفاق. مهمتك هي مساعدة الطلاب في التفسير، أحكام التجويد، وتقديم نصائح لحفظ القرآن. أجب باللغة العربية بأسلوب مشجع وواضح.",
      }
    });
    return response.text || "عذراً، لم أستطع معالجة طلبك حالياً.";
  } catch (error) {
    console.error("AI Error:", error);
    return "حدث خطأ في الاتصال بالمعلم الذكي.";
  }
};

export const getRecitationFeedback = async (audioBase64: string, verseText: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: audioBase64, mimeType: 'audio/pcm;rate=16000' } },
          { text: `قارن هذا التسجيل الصوتي مع هذه الآية: "${verseText}". هل القراءة صحيحة؟ قدم ملاحظات بسيطة حول التجويد والمخارج باللغة العربية.` }
        ]
      }
    });
    return response.text || "لم أتمكن من تحليل التسجيل.";
  } catch (error) {
    console.error("Audio Analysis Error:", error);
    return "خطأ في تحليل الصوت.";
  }
};

