import React, { useState, useRef, useEffect } from 'react';
import { getAIAssistance } from '../services/geminiService';
import { ChatMessage } from '../types';

const AIConsultant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'أهلاً بك يا بني. أنا معلمك الذكي في منصة آفاق. كيف يمكنني مساعدتك اليوم في فهم أو حفظ القرآن الكريم؟' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const responseText = await getAIAssistance(input);
    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-6 bg-emerald-800 text-white flex items-center gap-4">
        <div className="w-12 h-12 bg-emerald-100 rounded-2xl flex items-center justify-center text-3xl">🤖</div>
        <div>
          <h2 className="text-xl font-bold">المعلم الذكي</h2>
          <p className="text-emerald-200 text-xs">متاح دائماً لمساعدتك في رحلة الحفظ</p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
            <div className={`max-w-[80%] p-5 rounded-3xl text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
              ? 'bg-emerald-600 text-white rounded-br-none' 
              : 'bg-white text-slate-800 rounded-bl-none border border-slate-100'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-end">
            <div className="bg-white p-4 rounded-3xl rounded-bl-none border border-slate-100 flex gap-1">
              <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-100"></div>
              <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-200"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-100">
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200 focus-within:border-emerald-500 transition-colors">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="اسأل المعلم عن التفسير أو التجويد..."
            className="flex-1 bg-transparent border-none focus:ring-0 px-4 py-2 text-slate-800"
          />
          <button 
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="bg-emerald-600 text-white w-12 h-12 rounded-xl flex items-center justify-center hover:bg-emerald-700 disabled:bg-slate-300 transition-colors"
          >
            ✈️
          </button>
        </div>
        <p className="text-[10px] text-slate-400 mt-3 text-center">
          المعلم الذكي هو أداة مساعدة، يُنصح دائماً بمراجعة المشايخ المعتمدين في الأحكام الشرعية.
        </p>
      </div>
    </div>
  );
};

export default AIConsultant;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import QuranReader from './components/QuranReader';
import AIConsultant from './components/AIConsultant';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'quran':
        return <QuranReader />;
      case 'assistant':
        return <AIConsultant />;
      case 'progress':
        return (
          <div className="bg-white p-12 rounded-3xl shadow-sm border border-slate-100 text-center space-y-6">
            <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto text-5xl">🏆</div>
            <h2 className="text-2xl font-bold text-slate-800">سجل الإنجازات</h2>
            <p className="text-slate-500">هنا ستجد الأوسمة والشهادات التي حصلت عليها خلال رحلة الحفظ.</p>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6 pt-8">
              {[
                { title: 'بداية مباركة', color: 'blue' },
                { title: 'حفظ الجزء 30', color: 'emerald' },
                { title: 'أسبوع متواصل', color: 'amber' },
                { title: 'تجويد ممتاز', color: 'purple' },
              ].map((badge, i) => (
                <div key={i} className="flex flex-col items-center gap-3">
