      <div className="relative h-full">
        <button 
          onClick={handleLogout}
          className="fixed bottom-8 left-8 bg-white/80 backdrop-blur-sm border border-slate-200 text-slate-400 hover:text-red-500 px-4 py-2 rounded-xl text-[10px] font-bold shadow-sm transition-all z-50 flex items-center gap-2 print:hidden"
        >
          <span>🚪</span> تسجيل الخروج / تبديل الحساب
