                      🔒
                    </div>
                    <span className="text-sm font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{badge.title}</span>
                  </div>
                );
              })}
            </div>
          </div>
        );
      default:
        return <Dashboard />;
    }
  };

  const renderContent = () => {
    if (userRole === 'manager') return renderManagerContent();
    if (userRole === 'teacher') return renderTeacherContent();
    return renderStudentContent();
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={userRole} 
      setUserRole={setUserRole}
    >
      <div className="relative h-full">
        <button 
          onClick={handleLogout}
          className="fixed bottom-8 left-8 bg-white/80 backdrop-blur-sm border border-slate-200 text-slate-400 hover:text-red-500 px-4 py-2 rounded-xl text-[10px] font-bold shadow-sm transition-all z-50 flex items-center gap-2 print:hidden"
        >
          <span>🚪</span> تسجيل الخروج / تبديل الحساب
        </button>
        {renderContent()}
      </div>
    </Layout>
  );
};

