  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const roleData = roles.find(r => r.id === selectedRole);
    if (roleData && passcode === roleData.correctPass) {
      onSelectRole(selectedRole!);
    } else {
      setError('رمز الوصول غير صحيح، يرجى المحاولة مرة أخرى');
    }
  };

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col items-center justify-center p-6 text-center font-sans relative overflow-hidden">
      {/* Decorative Background Elements */}
      <div className="absolute top-[-10%] right-[-10%] w-[40%] h-[40%] bg-emerald-50 rounded-full blur-[120px] opacity-60"></div>
      <div className="absolute bottom-[-10%] left-[-10%] w-[30%] h-[30%] bg-amber-50 rounded-full blur-[100px] opacity-40"></div>

      {/* Header Section */}
      <div className="mb-20 animate-fadeIn relative z-10">
        <div className="w-20 h-20 bg-emerald-800 rounded-[28px] flex items-center justify-center text-white text-4xl font-black mx-auto mb-6 shadow-2xl shadow-emerald-200">
          آ
        </div>
        <h1 className="text-5xl font-black text-[#2D5A43] mb-4 quran-font tracking-tight">منصة آفاق</h1>
        <p className="text-[#64748B] text-lg font-medium opacity-80">بوابتكم نحو إتقان كتاب الله عز وجل</p>
      </div>

      {/* Roles Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-10 max-w-6xl w-full px-4 relative z-10">
        {roles.map((role) => (
          <div 
            key={role.id}
            onClick={() => handleRoleClick(role)}
            className="group bg-white p-10 rounded-[40px] shadow-[0_4px_20px_rgba(0,0,0,0.02)] hover:shadow-[0_30px_60px_rgba(0,0,0,0.1)] transition-all duration-500 cursor-pointer border border-[#F1F5F9] flex flex-col items-center transform hover:-translate-y-3 relative overflow-hidden"
          >
            <div className={`absolute top-0 left-0 right-0 h-2 opacity-0 group-hover:opacity-100 transition-opacity ${
              role.id === 'student' ? 'bg-emerald-500' :
              role.id === 'teacher' ? 'bg-amber-500' : 'bg-slate-500'
            }`}></div>

            <div className={`w-24 h-24 rounded-[30px] mb-8 flex items-center justify-center text-5xl transition-all duration-500 group-hover:scale-110 shadow-inner ${role.iconBg} ${role.iconColor}`}>
              {role.icon}
            </div>

            <h2 className="text-2xl font-black text-[#1E293B] mb-3">{role.title}</h2>
            <p className="text-[#94A3B8] text-sm mb-10 leading-relaxed font-medium max-w-[200px]">{role.desc}</p>

            <div className="mt-auto flex items-center gap-2 text-[#64748B] group-hover:text-[#2D5A43] font-bold transition-all">
              <span className="text-sm">دخول البوابة</span>
              <span className="text-lg transition-transform group-hover:translate-x-[-5px]">←</span>
            </div>
          </div>
        ))}
      </div>

      {/* Login Modal */}
      {showLogin && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-emerald-950/20 backdrop-blur-xl animate-fadeIn">
          <div className="bg-white w-full max-w-sm rounded-[45px] shadow-2xl p-10 relative overflow-hidden animate-scaleIn">
             <button 
              onClick={() => setShowLogin(false)}
              className="absolute top-6 left-6 w-10 h-10 flex items-center justify-center rounded-2xl hover:bg-slate-100 text-slate-400 transition-colors"
             >
               ✕
             </button>

             <div className="text-center space-y-6">
                <div className="w-20 h-20 bg-slate-50 rounded-3xl flex items-center justify-center text-4xl mx-auto shadow-inner">
                  🔐
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-800 mb-2">تسجيل دخول {selectedRole === 'teacher' ? 'المعلم' : 'المدير'}</h3>
                  <p className="text-sm text-slate-400 font-medium">يرجى إدخال رمز الوصول الخاص بالمنصة</p>
                </div>

                <form onSubmit={handleLogin} className="space-y-4">
                  <input 
                    autoFocus
                    type="password"
                    value={passcode}
                    onChange={(e) => setPasscode(e.target.value)}
                    placeholder="••••"
                    className="w-full text-center text-2xl tracking-[0.5em] py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-emerald-500 transition-all font-mono"
                  />
                  {error && <p className="text-red-500 text-[10px] font-bold animate-shake">{error}</p>}

                  <button 
                    type="submit"
                    className="w-full py-4 bg-emerald-800 text-white rounded-2xl font-black text-sm hover:bg-emerald-900 transition-all shadow-xl shadow-emerald-100 mt-4"
                  >
                    تأكيد الدخول
                  </button>

                  <p className="text-[9px] text-slate-300 font-bold uppercase tracking-widest pt-2">
                    تواصل مع الإدارة إذا فقدت الرمز
                  </p>
                </form>
             </div>
          </div>
        </div>
      )}

      {/* Footer Info */}
      <div className="mt-24 text-[#94A3B8] text-[10px] font-bold tracking-widest opacity-60 relative z-10">
        <p>نظام آفاق التعليمي الموحد • الإصدار 2.5</p>
      </div>
    </div>
  );
};

