];

interface ManagerTeachersProps {
  onEnterTeacherPortal?: () => void;
}

const ManagerTeachers: React.FC<ManagerTeachersProps> = ({ onEnterTeacherPortal }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [teachers, setTeachers] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    fullName: '',
    specialty: 'حفظ ومراجعة',
    status: 'نشط'
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_teachers');
    if (saved) {
      setTeachers(JSON.parse(saved));
    } else {
      setTeachers(INITIAL_TEACHERS);
      localStorage.setItem('afaq_teachers', JSON.stringify(INITIAL_TEACHERS));
    }
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setFormData({ fullName: '', specialty: 'حفظ ومراجعة', status: 'نشط' });
    setShowModal(true);
  };

  const openEditModal = (teacher: any) => {
    setEditingId(teacher.id);
    setFormData({
      fullName: teacher.name,
      specialty: teacher.specialty,
      status: teacher.status
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedTeachers;

    if (editingId) {
      updatedTeachers = teachers.map(t => 
        t.id === editingId 
          ? { ...t, name: formData.fullName, specialty: formData.specialty, status: formData.status } 
          : t
      );
    } else {
      const newTeacher = {
        id: Math.random().toString(36).substr(2, 9),
        name: formData.fullName,
        specialty: formData.specialty,
        students: 0,
        status: formData.status,
        joinDate: new Date().toISOString().split('T')[0]
      };
      updatedTeachers = [newTeacher, ...teachers];
    }

    setTeachers(updatedTeachers);
    localStorage.setItem('afaq_teachers', JSON.stringify(updatedTeachers));
    setShowModal(false);
  };

  const initiateDelete = (id: string) => {
    setSelectedTeacherId(id);
    setShowDeleteConfirm(true);
  };

  const confirmDelete = () => {
    if (selectedTeacherId) {
      const updated = teachers.filter(t => t.id !== selectedTeacherId);
      setTeachers(updated);
      localStorage.setItem('afaq_teachers', JSON.stringify(updated));
      setShowDeleteConfirm(false);
      setSelectedTeacherId(null);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">إدارة الكادر التعليمي</h2>
          <p className="text-slate-500 text-sm">إضافة، تعديل، أو حذف بيانات المعلمين</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 flex items-center gap-2"
        >
          <span>➕</span> إضافة معلم جديد
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-slate-50 text-slate-400 text-xs font-bold uppercase tracking-wider">
                <th className="px-8 py-5">المعلم</th>
                <th className="px-6 py-5">التخصص</th>
                <th className="px-6 py-5 text-center">الطلاب</th>
                <th className="px-6 py-5 text-center">الحالة</th>
                <th className="px-8 py-5 text-left">الإجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {teachers.map((teacher) => (
                <tr key={teacher.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-emerald-100 text-emerald-700 flex items-center justify-center font-bold">
                        {teacher.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-700">{teacher.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-5 text-sm text-slate-600">{teacher.specialty}</td>
                  <td className="px-6 py-5 text-sm font-bold text-slate-800 text-center">{teacher.students}</td>
                  <td className="px-6 py-5 text-center">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${
                      teacher.status === 'نشط' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      {teacher.status}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-left">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      {onEnterTeacherPortal && (
                        <button 
                          onClick={onEnterTeacherPortal}
                          className="p-2.5 hover:bg-emerald-50 text-emerald-600 rounded-xl transition-all border border-transparent hover:border-emerald-100"
                          title="دخول بوابة المعلم"
                        >
                          🔑
                        </button>
                      )}
                      <button 
                        onClick={() => openEditModal(teacher)}
                        className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100"
                        title="تعديل البيانات"
                      >
                        📝
                      </button>
                      <button 
                        onClick={() => initiateDelete(teacher.id)}
                        className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100"
                        title="حذف المعلم"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal: Add/Edit Teacher */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg rounded-[40px] shadow-2xl overflow-hidden animate-scaleIn">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">
                {editingId ? 'تعديل بيانات المعلم' : 'إضافة معلم جديد'}
              </h3>
              <button onClick={() => setShowModal(false)} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-200 transition-colors text-slate-400">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wider">الاسم الكامل</label>
                <input 
                  required
                  value={formData.fullName}
                  type="text" 
                  className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
                  placeholder="مثال: د. عبدالله محمد"
                  onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                />
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wider">التخصص التعليمي</label>
                <select 
                  className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer"
                  value={formData.specialty}
                  onChange={(e) => setFormData({...formData, specialty: e.target.value})}
                >
                  <option>حفظ ومراجعة</option>
                  <option>تجويد وقراءات</option>
                  <option>تفسير</option>
                  <option>القراءات العشر</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wider">الحالة الحالية</label>
                <select 
                  className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer"
                  value={formData.status}
                  onChange={(e) => setFormData({...formData, status: e.target.value})}
                >
                  <option value="نشط">نشط</option>
                  <option value="في إجازة">في إجازة</option>
                  <option value="غير متاح">غير متاح</option>
                </select>
              </div>

              <div className="pt-4 flex gap-4">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100">
                  {editingId ? 'حفظ التعديلات' : 'إضافة المعلم'}
                </button>
                <button type="button" onClick={() => setShowModal(false)} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-200 transition-all">إلغاء</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal: Delete Confirmation */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[40px] shadow-2xl p-10 text-center space-y-6 animate-scaleIn">
            <div className="w-20 h-20 bg-red-50 text-red-500 rounded-3xl flex items-center justify-center text-4xl mx-auto shadow-inner border border-red-100">
              ⚠️
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 mb-2">تأكيد حذف المعلم</h3>
              <p className="text-sm text-slate-500 leading-relaxed">
                هل أنت متأكد من رغبتك في حذف هذا المعلم؟ سيتم إزالة كافة بياناته وارتباطاته بالحلقات، ولا يمكن التراجع عن هذا الإجراء.
              </p>
            </div>
            <div className="flex flex-col gap-3">
              <button 
                onClick={confirmDelete}
                className="w-full py-4 bg-red-600 text-white rounded-2xl font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-100"
              >
                نعم، احذف المعلم
              </button>
              <button 
                onClick={() => { setShowDeleteConfirm(false); setSelectedTeacherId(null); }}
                className="w-full py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-200 transition-all"
              >
                تراجع
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerTeachers;

import React, { useState } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import ManagerDashboard from './components/ManagerDashboard';
import ManagerTeachers from './components/ManagerTeachers';
import ManagerStudents from './components/ManagerStudents';
import ManagerReports from './components/ManagerReports';
import ManagerCircles from './components/ManagerCircles';
import TeacherDashboard from './components/TeacherDashboard';
import TeacherStudents from './components/TeacherStudents';
import TeacherSessions from './components/TeacherSessions';
import TeacherCurriculum from './components/TeacherCurriculum';
import QuranReader from './components/QuranReader';
import AIConsultant from './components/AIConsultant';
import { UserRole } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [isManagerShadowing, setIsManagerShadowing] = useState(false);

  const handleRoleSelection = (role: UserRole) => {
    setUserRole(role);
    setActiveTab('dashboard');
    setIsManagerShadowing(false); // Reset shadowing when selecting from landing
  };

  const enterTeacherPortalAsManager = () => {
    setUserRole('teacher');
    setActiveTab('dashboard');
    setIsManagerShadowing(true);
  };

  const exitTeacherPortalToManager = () => {
    setUserRole('manager');
    setActiveTab('teachers'); // Return to teachers list
    setIsManagerShadowing(false);
  };

  const handleLogout = () => {
    setUserRole(null);
    setIsManagerShadowing(false);
  };

  if (!userRole) {
    return <LandingPage onSelectRole={handleRoleSelection} />;
  }

  const renderManagerContent = () => {
    switch (activeTab) {
      case 'dashboard': return <ManagerDashboard />;
      case 'teachers': 
        return <ManagerTeachers 
          onEnterTeacherPortal={enterTeacherPortalAsManager} 
        />;
      case 'circles': return <ManagerCircles />;
      case 'students_all': return <ManagerStudents />;
      case 'reports': return <ManagerReports />;
      default: return <ManagerDashboard />;
    }
  };

  const renderTeacherContent = () => {
    switch (activeTab) {
      case 'dashboard': return <TeacherDashboard />;
      case 'my_students': return <TeacherStudents />;
      case 'sessions': return <TeacherSessions />;
      case 'curriculum': return <TeacherCurriculum />;
      default: return <TeacherDashboard />;
    }
  };

  const renderStudentContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard />;
      case 'quran': return <QuranReader />;
      case 'assistant': return <AIConsultant />;
      case 'progress':
        return (
          <div className="bg-white p-12 rounded-[40px] shadow-sm border border-slate-100 text-center space-y-6 animate-fadeIn">
            <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto text-5xl">🏆</div>
            <h2 className="text-2xl font-bold text-slate-800">سجل الإنجازات</h2>
            <p className="text-slate-500 max-w-md mx-auto">هنا ستجد الأوسمة والشهادات التي حصلت عليها خلال رحلة الحفظ المباركة في منصة آفاق.</p>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 pt-12">
              {[
                { title: 'بداية مباركة', color: 'blue', icon: '✨' },
                { title: 'حفظ الجزء 30', color: 'emerald', icon: '📜' },
                { title: 'أسبوع متواصل', color: 'amber', icon: '🔥' },
                { title: 'تجويد ممتاز', color: 'purple', icon: '🔊' },
              ].map((badge, i) => (
                <div key={i} className="flex flex-col items-center gap-4 group">
                  <div className="w-20 h-20 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl opacity-50 grayscale group-hover:grayscale-0 group-hover:opacity-100 transition-all cursor-help relative">
                    🔒
                  </div>
                  <span className="text-sm font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{badge.title}</span>
                </div>
              ))}
            </div>
          </div>
        );
      default: return <Dashboard />;
    }
  };

  const renderContent = () => {
    if (userRole === 'manager') return renderManagerContent();
    if (userRole === 'teacher') return renderTeacherContent();
    return renderStudentContent();
  };

  return (
    <div className="relative h-screen overflow-hidden flex flex-col">
      {/* Shadowing Notification Bar */}
      {isManagerShadowing && (
        <div className="bg-emerald-950 text-white px-8 py-3 flex items-center justify-between z-[60] shadow-xl animate-fadeIn">
          <div className="flex items-center gap-4">
            <span className="animate-pulse flex h-3 w-3 rounded-full bg-amber-400"></span>
            <p className="text-sm font-bold">وضع المعاينة: أنت الآن تتصفح المنصة بصلاحية <span className="text-amber-400">معلم</span></p>
          </div>
          <button 
            onClick={exitTeacherPortalToManager}
            className="bg-amber-500 hover:bg-amber-400 text-emerald-950 px-5 py-1.5 rounded-xl text-xs font-black transition-all flex items-center gap-2"
          >
            ↩ العودة لبوابة المدير
          </button>
        </div>
      )}

      <div className="flex-1 overflow-hidden">
        <Layout 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
          userRole={userRole} 
          setUserRole={setUserRole}
        >
          <div className="relative h-full">
            <button 
              onClick={handleLogout}
              className="fixed bottom-8 left-8 bg-white/90 backdrop-blur-sm border border-slate-200 text-slate-400 hover:text-red-500 px-4 py-2 rounded-xl text-[10px] font-bold shadow-sm transition-all z-50 flex items-center gap-2 print:hidden"
            >
              <span>🚪</span> تبديل الحساب / خروج
            </button>
            {renderContent()}
          </div>
        </Layout>
      </div>
    </div>
  );
};

export default App;

