const ManagerStudents: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [students, setStudents] = useState<any[]>([]);

  const [formData, setFormData] = useState({
    fullName: '',
    selectedCircle: '',
    memorized: '',
    hifdhSurah: 'البقرة',
    hifdhLines: 5,
    tathbeetSurah: 'الفاتحة',
    tathbeetLines: 7,
    reviewSurah: 'النبأ',
    reviewLines: 20
  });

  const circles = ['حلقة الريان', 'حلقة الفردوس', 'حلقة التميز', 'حلقة الأبرار'];

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) {
      setStudents(JSON.parse(saved));
    } else {
      setStudents(INITIAL_STUDENTS);
      localStorage.setItem('afaq_students', JSON.stringify(INITIAL_STUDENTS));
    }
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setFormData({ 
      fullName: '', 
      selectedCircle: '', 
      memorized: '',
      hifdhSurah: 'البقرة',
      hifdhLines: 5,
      tathbeetSurah: 'الفاتحة',
      tathbeetLines: 7,
      reviewSurah: 'النبأ',
      reviewLines: 20
    });
    setShowModal(true);
  };

  const openEditModal = (student: any) => {
    setEditingId(student.id);
    setFormData({
      fullName: student.name,
      selectedCircle: student.circle,
      memorized: student.memorized,
      hifdhSurah: student.plan?.hifdh?.surah || 'البقرة',
      hifdhLines: student.plan?.hifdh?.lines || 5,
      tathbeetSurah: student.plan?.tathbeet?.surah || 'الفاتحة',
      tathbeetLines: student.plan?.tathbeet?.lines || 7,
      reviewSurah: student.plan?.review?.surah || 'النبأ',
      reviewLines: student.plan?.review?.lines || 20
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const studyPlan: StudyPlan = {
      hifdh: { surah: formData.hifdhSurah, lines: formData.hifdhLines },
      tathbeet: { surah: formData.tathbeetSurah, lines: formData.tathbeetLines },
      review: { surah: formData.reviewSurah, lines: formData.reviewLines },
      lastUpdated: new Date().toISOString()
    };

    let updated;
    if (editingId) {
      updated = students.map(s => 
        s.id === editingId 
          ? { ...s, name: formData.fullName, circle: formData.selectedCircle, memorized: formData.memorized, plan: studyPlan } 
          : s
      );
    } else {
      const newStudent = {
        id: Math.random().toString(36).substr(2, 5).toUpperCase(),
        name: formData.fullName,
        level: 'جديد',
        memorized: formData.memorized || 'لم يبدأ',
        teacher: 'غير محدد',
        circle: formData.selectedCircle || 'غير محدد',
        lastActive: 'الآن',
        progress: 0,
        plan: studyPlan
      };
      updated = [newStudent, ...students];
    }

    setStudents(updated);
    localStorage.setItem('afaq_students', JSON.stringify(updated));
    setShowModal(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف ملف هذا الطالب نهائياً؟')) {
      const updated = students.filter(s => s.id !== id);
      setStudents(updated);
      localStorage.setItem('afaq_students', JSON.stringify(updated));
    }
  };

  const inputClass = "w-full px-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium";
