          <p className="text-slate-500 text-sm">إدارة وتعديل بيانات الطلاب وخططهم الدراسية</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 flex items-center gap-2"
        >
          <span>➕</span> إضافة طالب جديد
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-8 py-4 text-xs font-bold text-slate-400 uppercase">اسم الطالب</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">الحلقة</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">الخطة الحالية</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">الإنجاز</th>
                <th className="px-8 py-4 text-xs font-bold text-slate-400 uppercase text-left">الإجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {students.map((st) => (
                <tr key={st.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 text-sm">{st.name}</span>
                      <span className="text-[10px] text-slate-400">كود: {st.id}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-[10px] font-bold px-3 py-1 bg-amber-50 rounded-full text-amber-700 border border-amber-100">
                      {st.circle}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    {st.plan ? (
                      <div className="text-[10px] space-y-0.5">
                        <p className="text-emerald-600 font-bold">✨ حفظ: {st.plan.hifdh.surah}</p>
                        <p className="text-blue-600 font-bold">📌 تثبيت: {st.plan.tathbeet.surah}</p>
                      </div>
                    ) : (
                      <span className="text-[10px] text-slate-300">لا يوجد خطة</span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-center">
                    <div className="flex items-center gap-2 justify-center">
                      <div className="w-16 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full bg-emerald-500" style={{ width: `${st.progress || 0}%` }}></div>
                      </div>
                      <span className="text-[10px] font-bold text-slate-500">{st.progress || 0}%</span>
                    </div>
                  </td>
                  <td className="px-8 py-4 text-left">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => openEditModal(st)} className="p-2 hover:bg-blue-50 text-blue-600 rounded-lg transition-colors border border-transparent hover:border-blue-100" title="تعديل البيانات والخطة">📝</button>
                      <button onClick={() => handleDelete(st.id)} className="p-2 hover:bg-red-50 text-red-600 rounded-lg transition-colors border border-transparent hover:border-red-100" title="حذف">🗑️</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden animate-scaleIn max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50 shrink-0">
              <div>
                <h3 className="text-xl font-bold text-slate-800">
                  {editingId ? 'تعديل بيانات وخطة الطالب' : 'تسجيل طالب جديد مع خطة الحفظ'}
                </h3>
                <p className="text-xs text-slate-400">أدخل المعلومات الشخصية وحدد المسار التعليمي</p>
              </div>
              <button onClick={() => setShowModal(false)} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-200 transition-colors text-slate-400">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8">
              {/* Basic Info */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2">
                  <label className={labelClass}>الاسم الرباعي</label>
                  <input required value={formData.fullName} type="text" className={inputClass} placeholder="أدخل اسم الطالب الكامل" onChange={(e) => setFormData({...formData, fullName: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>الحلقة</label>
                  <select required className={inputClass} value={formData.selectedCircle} onChange={(e) => setFormData({...formData, selectedCircle: e.target.value})}>
                    <option value="">اختر الحلقة...</option>
                    {circles.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>مقدار الحفظ السابق</label>
                  <input value={formData.memorized} type="text" className={inputClass} placeholder="مثال: 5 أجزاء" onChange={(e) => setFormData({...formData, memorized: e.target.value})} />
                </div>
              </div>

              <div className="h-px bg-slate-100"></div>

              {/* Study Plan Section */}
              <div className="space-y-6">
                <h4 className="text-sm font-black text-slate-800 flex items-center gap-2">
