                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {/* New Hifdh */}
                  <div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100 space-y-3">
                    <p className="text-[10px] font-black text-emerald-700 uppercase tracking-widest">✨ الحفظ الجديد</p>
                    <div>
                      <label className="text-[9px] font-bold text-slate-400 block mb-1">بداية السورة</label>
                      <select 
                        className="w-full text-xs p-2 rounded-lg border border-emerald-200 outline-none focus:ring-1 focus:ring-emerald-500"
