                      />
                    </div>
                  </div>

                  {/* Tathbeet */}
                  <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 space-y-3">
                    <p className="text-[10px] font-black text-blue-700 uppercase tracking-widest">📌 التثبيت</p>
                    <div>
                      <label className="text-[9px] font-bold text-slate-400 block mb-1">من سورة</label>
                      <select 
                        className="w-full text-xs p-2 rounded-lg border border-blue-200 outline-none focus:ring-1 focus:ring-blue-500"
                        value={formData.tathbeetSurah}
                        onChange={(e) => setFormData({...formData, tathbeetSurah: e.target.value})}
                      >
                        {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                      </select>
                    </div>
                    <div>
                      <label className="text-[9px] font-bold text-slate-400 block mb-1">عدد الأسطر</label>
                      <input 
                        type="number" 
