                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-sm">{st.name}</span>
                        <span className="text-[9px] text-slate-400 font-bold uppercase">{st.circle}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-0.5">
                      <span className="text-xs font-bold text-slate-600">{st.idNumber || '—'}</span>
                      <span className="text-[10px] text-slate-400 font-medium">{st.nationality} • {st.birthDate ? new Date().getFullYear() - new Date(st.birthDate).getFullYear() + ' سنة' : ''}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {st.plan ? (
                      <div className="flex gap-2">
