        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 flex items-center gap-2"
        >
          <span>➕</span> إضافة معلم
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase">المعلم</th>
              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase">التخصص</th>
              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase text-center">الحالة</th>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase text-left">الإجراءات</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {teachers.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-bold">{t.name.charAt(0)}</div>
                    <span className="font-bold text-slate-700">{t.name}</span>
                  </div>
                </td>
                <td className="px-6 py-5 text-sm text-slate-500 font-medium">{t.specialty}</td>
                <td className="px-6 py-5 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${t.status === 'نشط' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                    {t.status}
