import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

const INITIAL_STUDENTS = [
  { 
    id: 'S101', 
    name: 'يوسف العتيبي', 
    memorized: '15 جزء', 
    teacher: 'د. عبد الله الماجد', 
    circle: 'حلقة الريان', 
    progress: 85,
    idNumber: '1092837465',
    birthDate: '2010-05-15',
    nationality: 'سعودي',
    plan: {
      hifdh: { surah: 'البقرة', lines: 5 },
      tathbeet: { surah: 'الفاتحة', lines: 10 },
      review: { surah: 'النبأ', lines: 20 },
      lastUpdated: new Date().toISOString()
    }
  },
  { 
    id: 'S102', 
    name: 'ياسين فهد', 
    memorized: '8 أجزاء', 
    teacher: 'أ. سارة المنصور', 
    circle: 'حلقة الفردوس', 
    progress: 40,
    idNumber: '1088273645',
    birthDate: '2012-08-20',
    nationality: 'سعودي'
  },
];

const ManagerStudents: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [availableCircles, setAvailableCircles] = useState<any[]>([]);

  const [formData, setFormData] = useState({
    fullName: '',
    selectedCircle: '',
    memorized: '',
    idNumber: '',
    birthDate: '',
    nationality: 'سعودي',
    hifdhSurah: 'البقرة',
    hifdhLines: 5,
    tathbeetSurah: 'الفاتحة',
    tathbeetLines: 7,
    reviewSurah: 'النبأ',
    reviewLines: 20
  });

  useEffect(() => {
    // جلب الطلاب
    const savedStudents = localStorage.getItem('afaq_students');
    if (savedStudents) {
      setStudents(JSON.parse(savedStudents));
    } else {
      setStudents(INITIAL_STUDENTS);
      localStorage.setItem('afaq_students', JSON.stringify(INITIAL_STUDENTS));
    }

    // جلب الحلقات المتاحة ديناميكياً
    const savedCircles = localStorage.getItem('afaq_circles');
    if (savedCircles) {
      setAvailableCircles(JSON.parse(savedCircles));
    }
  }, [showModal]); // تحديث القائمة عند فتح النافذة

  const openAddModal = () => {
    setEditingId(null);
    setFormData({ 
      fullName: '', 
      selectedCircle: '', 
      memorized: '',
      idNumber: '',
      birthDate: '',
      nationality: 'سعودي',
      hifdhSurah: 'البقرة',
      hifdhLines: 5,
      tathbeetSurah: 'الفاتحة',
      tathbeetLines: 10,
      reviewSurah: 'النبأ',
      reviewLines: 20
    });
    setShowModal(true);
  };

  const openEditModal = (student: any) => {
    setEditingId(student.id);
    setFormData({
      fullName: student.name,
      selectedCircle: student.circle,
      memorized: student.memorized,
      idNumber: student.idNumber || '',
      birthDate: student.birthDate || '',
      nationality: student.nationality || 'سعودي',
      hifdhSurah: student.plan?.hifdh?.surah || 'البقرة',
      hifdhLines: student.plan?.hifdh?.lines || 5,
      tathbeetSurah: student.plan?.tathbeet?.surah || 'الفاتحة',
      tathbeetLines: student.plan?.tathbeet?.lines || 10,
      reviewSurah: student.plan?.review?.surah || 'النبأ',
      reviewLines: student.plan?.review?.lines || 20
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const studyPlan: StudyPlan = {
      hifdh: { surah: formData.hifdhSurah, lines: formData.hifdhLines },
      tathbeet: { surah: formData.tathbeetSurah, lines: formData.tathbeetLines },
      review: { surah: formData.reviewSurah, lines: formData.reviewLines },
      lastUpdated: new Date().toISOString()
    };

    let updated;
    if (editingId) {
      updated = students.map(s => 
        s.id === editingId 
          ? { ...s, 
              name: formData.fullName, 
              circle: formData.selectedCircle, 
              memorized: formData.memorized, 
              idNumber: formData.idNumber,
              birthDate: formData.birthDate,
              nationality: formData.nationality,
              plan: studyPlan 
            } 
          : s
      );
    } else {
      const newStudent = {
        id: 'S' + Math.floor(100 + Math.random() * 900),
        name: formData.fullName,
        memorized: formData.memorized || 'لم يبدأ',
        teacher: availableCircles.find(c => c.name === formData.selectedCircle)?.teacher || 'بانتظار التعيين',
        circle: formData.selectedCircle || 'غير محدد',
        idNumber: formData.idNumber,
        birthDate: formData.birthDate,
        nationality: formData.nationality,
        progress: 0,
        plan: studyPlan,
        joinDate: new Date().toISOString().split('T')[0]
      };
      updated = [newStudent, ...students];
    }

    setStudents(updated);
    localStorage.setItem('afaq_students', JSON.stringify(updated));
    setShowModal(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('🚨 هل أنت متأكد من حذف هذا الطالب نهائياً؟')) {
      const updated = students.filter(s => s.id !== id);
      setStudents(updated);
      localStorage.setItem('afaq_students', JSON.stringify(updated));
    }
  };

  const inputClass = "w-full px-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium";
  const labelClass = "block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest";

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">شؤون الطلاب</h2>
          <p className="text-slate-500 text-sm">إدارة شاملة لملفات الطلاب والخطط الدراسية</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 flex items-center gap-2"
        >
          <span>➕</span> تسجيل طالب جديد
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-8 py-4 text-xs font-bold text-slate-400 uppercase">اسم الطالب</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">الحلقة</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">الهوية</th>
                <th className="px-8 py-4 text-xs font-bold text-slate-400 uppercase text-left">الإدارة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {students.length > 0 ? students.map((st) => (
                <tr key={st.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-bold text-sm">
                        {st.name.charAt(0)}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-sm">{st.name}</span>
                        <span className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">{st.joinDate}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-700 rounded-full text-[10px] font-black uppercase">
                      {st.circle}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-xs font-medium text-slate-500">{st.idNumber || '—'}</span>
                  </td>
                  <td className="px-8 py-4 text-left">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => openEditModal(st)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100">📝</button>
                      <button onClick={() => handleDelete(st.id)} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100">🗑️</button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={4} className="px-8 py-12 text-center text-slate-300 italic">لا يوجد طلاب مسجلون</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-3xl rounded-[40px] shadow-2xl overflow-hidden animate-scaleIn max-h-[95vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50 shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-emerald-600 text-white rounded-2xl flex items-center justify-center text-xl shadow-lg shadow-emerald-200">📖</div>
                <div>
                  <h3 className="text-xl font-bold text-slate-800">
                    {editingId ? 'تعديل ملف الطالب' : 'تسجيل طالب جديد'}
                  </h3>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">إدارة البيانات الشخصية والورد اليومي</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-200 transition-colors text-slate-400">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-10">
              <section className="space-y-6">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] border-b pb-2">👤 بيانات الطالب الرسمية</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  <div className="lg:col-span-2">
                    <label className={labelClass}>الاسم الكامل</label>
                    <input required value={formData.fullName} type="text" className={inputClass} onChange={(e) => setFormData({...formData, fullName: e.target.value})} />
                  </div>
                  <div>
                    <label className={labelClass}>رقم الهوية</label>
                    <input required value={formData.idNumber} type="text" className={inputClass} onChange={(e) => setFormData({...formData, idNumber: e.target.value})} />
                  </div>
                  <div>
                    <label className={labelClass}>الجنسية</label>
                    <input required value={formData.nationality} type="text" className={inputClass} onChange={(e) => setFormData({...formData, nationality: e.target.value})} />
                  </div>
                  <div>
                    <label className={labelClass}>اختيار الحلقة</label>
                    <select required className={inputClass} value={formData.selectedCircle} onChange={(e) => setFormData({...formData, selectedCircle: e.target.value})}>
                      <option value="">اختر من الحلقات النشطة...</option>
                      {availableCircles.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                      {availableCircles.length === 0 && <option disabled>لا توجد حلقات نشطة! أنشئ حلقة أولاً.</option>}
                    </select>
                  </div>
                </div>
              </section>

              <section className="space-y-6">
                <h4 className="text-xs font-black text-emerald-600 uppercase tracking-[0.2em] border-b border-emerald-100 pb-2">✨ الورد القرآني اليومي</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="p-5 bg-emerald-50 rounded-3xl border border-emerald-100 space-y-4">
                    <p className="text-[10px] font-black text-emerald-700 uppercase tracking-widest text-center">حفظ جديد</p>
                    <select className="w-full text-xs p-2.5 rounded-xl border-emerald-200 outline-none" value={formData.hifdhSurah} onChange={(e) => setFormData({...formData, hifdhSurah: e.target.value})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                    <input type="number" className="w-full text-xs p-2.5 rounded-xl border-emerald-200 outline-none" value={formData.hifdhLines} onChange={(e) => setFormData({...formData, hifdhLines: parseInt(e.target.value)})} />
                  </div>
                  <div className="p-5 bg-blue-50 rounded-3xl border border-blue-100 space-y-4">
                    <p className="text-[10px] font-black text-blue-700 uppercase tracking-widest text-center">تثبيت</p>
                    <select className="w-full text-xs p-2.5 rounded-xl border-blue-200 outline-none" value={formData.tathbeetSurah} onChange={(e) => setFormData({...formData, tathbeetSurah: e.target.value})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                    <input type="number" className="w-full text-xs p-2.5 rounded-xl border-blue-200 outline-none" value={formData.tathbeetLines} onChange={(e) => setFormData({...formData, tathbeetLines: parseInt(e.target.value)})} />
                  </div>
                  <div className="p-5 bg-purple-50 rounded-3xl border border-purple-100 space-y-4">
                    <p className="text-[10px] font-black text-purple-700 uppercase tracking-widest text-center">مراجعة</p>
                    <select className="w-full text-xs p-2.5 rounded-xl border-purple-200 outline-none" value={formData.reviewSurah} onChange={(e) => setFormData({...formData, reviewSurah: e.target.value})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                    <input type="number" className="w-full text-xs p-2.5 rounded-xl border-purple-200 outline-none" value={formData.reviewLines} onChange={(e) => setFormData({...formData, reviewLines: parseInt(e.target.value)})} />
                  </div>
                </div>
              </section>

              <div className="pt-6 flex gap-4 shrink-0 pb-4">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black shadow-xl hover:bg-emerald-700 transition-all">
