const ManagerDashboard: React.FC = () => {
  const [counts, setCounts] = useState({
    students: 0,
    teachers: 0,
    circles: 0
  });

  useEffect(() => {
    // تحديث الأرقام من LocalStorage لضمان دقة البيانات بعد الحذف
    const updateStats = () => {
      const students = JSON.parse(localStorage.getItem('afaq_students') || '[]');
      const teachers = JSON.parse(localStorage.getItem('afaq_teachers') || '[]');
      const circles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

      setCounts({
        students: students.length,
        teachers: teachers.length,
        circles: circles.length
      });
    };

    updateStats();

    // الاستماع لتغييرات التخزين (في حال تم الحذف من نافذة أخرى)
    window.addEventListener('storage', updateStats);
    return () => window.removeEventListener('storage', updateStats);
  }, []);

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Overview Cards */}
