import React, { useState } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import ManagerDashboard from './components/ManagerDashboard';
import ManagerTeachers from './components/ManagerTeachers';
import ManagerStudents from './components/ManagerStudents';
import ManagerReports from './components/ManagerReports';
import ManagerCircles from './components/ManagerCircles';
import TeacherDashboard from './components/TeacherDashboard';
import TeacherStudents from './components/TeacherStudents';
import TeacherSessions from './components/TeacherSessions';
import TeacherCurriculum from './components/TeacherCurriculum';
import QuranReader from './components/QuranReader';
import AIConsultant from './components/AIConsultant';
import { UserRole } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [isManagerShadowing, setIsManagerShadowing] = useState(false);

  const handleRoleSelection = (role: UserRole) => {
    setUserRole(role);
    setActiveTab('dashboard');
    setIsManagerShadowing(false);
  };

  const enterTeacherPortalAsManager = () => {
    setUserRole('teacher');
    setActiveTab('dashboard');
    setIsManagerShadowing(true);
  };

  const exitTeacherPortalToManager = () => {
    setUserRole('manager');
    setActiveTab('teachers'); // العودة لقائمة المعلمين
    setIsManagerShadowing(false);
  };

  const handleLogout = () => {
    setUserRole(null);
    setIsManagerShadowing(false);
  };

  if (!userRole) {
    return <LandingPage onSelectRole={handleRoleSelection} />;
  }

  const renderManagerContent = () => {
    switch (activeTab) {
      case 'dashboard': return <ManagerDashboard />;
      case 'teachers': 
        return <ManagerTeachers 
          onEnterTeacherPortal={enterTeacherPortalAsManager} 
        />;
      case 'circles': return <ManagerCircles />;
      case 'students_all': return <ManagerStudents />;
      case 'reports': return <ManagerReports />;
      default: return <ManagerDashboard />;
    }
  };

  const renderTeacherContent = () => {
    switch (activeTab) {
      case 'dashboard': return <TeacherDashboard />;
      case 'my_students': return <TeacherStudents />;
      case 'sessions': return <TeacherSessions />;
      case 'curriculum': return <TeacherCurriculum />;
      default: return <TeacherDashboard />;
    }
  };

  const renderStudentContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard />;
      case 'quran': return <QuranReader />;
      case 'assistant': return <AIConsultant />;
      case 'progress':
        return (
          <div className="bg-white p-12 rounded-[40px] shadow-sm border border-slate-100 text-center space-y-6 animate-fadeIn">
            <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto text-5xl">🏆</div>
            <h2 className="text-2xl font-bold text-slate-800">سجل الإنجازات</h2>
            <p className="text-slate-500 max-w-md mx-auto">هنا ستجد الأوسمة والشهادات التي حصلت عليها خلال رحلة الحفظ المباركة في منصة آفاق.</p>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 pt-12">
              {[
                { title: 'بداية مباركة', color: 'blue', icon: '✨' },
                { title: 'حفظ الجزء 30', color: 'emerald', icon: '📜' },
                { title: 'أسبوع متواصل', color: 'amber', icon: '🔥' },
                { title: 'تجويد ممتاز', color: 'purple', icon: '🔊' },
              ].map((badge, i) => (
                <div key={i} className="flex flex-col items-center gap-4 group">
                  <div className="w-20 h-20 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl opacity-50 grayscale group-hover:grayscale-0 group-hover:opacity-100 transition-all cursor-help relative">
                    🔒
                  </div>
                  <span className="text-sm font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{badge.title}</span>
                </div>
              ))}
            </div>
          </div>
        );
      default: return <Dashboard />;
    }
  };

  const renderContent = () => {
    if (userRole === 'manager') return renderManagerContent();
    if (userRole === 'teacher') return renderTeacherContent();
    return renderStudentContent();
  };

  return (
    <div className="relative h-screen overflow-hidden flex flex-col">
      {/* شريط تنبيه وضع المعاينة للمدير */}
      {isManagerShadowing && (
        <div className="bg-emerald-950 text-white px-8 py-3 flex items-center justify-between z-[60] shadow-xl animate-fadeIn">
          <div className="flex items-center gap-4">
            <span className="animate-pulse flex h-3 w-3 rounded-full bg-amber-400"></span>
            <p className="text-sm font-bold">أنت الآن تتصفح المنصة بصلاحية <span className="text-amber-400">معلم</span> (وضع المعاينة)</p>
          </div>
          <button 
            onClick={exitTeacherPortalToManager}
            className="bg-amber-500 hover:bg-amber-400 text-emerald-950 px-6 py-2 rounded-xl text-xs font-black transition-all flex items-center gap-2 shadow-lg"
          >
            ↩ العودة لبوابة المدير
          </button>
        </div>
      )}

      <div className="flex-1 overflow-hidden">
        <Layout 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
          userRole={userRole} 
          setUserRole={setUserRole}
        >
          <div className="relative h-full">
            <button 
              onClick={handleLogout}
              className="fixed bottom-8 left-8 bg-white/90 backdrop-blur-sm border border-slate-200 text-slate-400 hover:text-red-500 px-4 py-2 rounded-xl text-[10px] font-bold shadow-sm transition-all z-50 flex items-center gap-2 print:hidden"
            >
              <span>🚪</span> تبديل الحساب / خروج
            </button>
            {renderContent()}
          </div>
        </Layout>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';

const INITIAL_TEACHERS = [
  { id: 'T1', name: 'د. عبد الله الماجد', specialty: 'تجويد وقراءات', students: 45, status: 'نشط', joinDate: '2023-01-10' },
  { id: 'T2', name: 'أ. سارة المنصور', specialty: 'حفظ ومراجعة', students: 38, status: 'نشط', joinDate: '2023-03-15' },
  { id: 'T3', name: 'أ. محمد العتيبي', specialty: 'تفسير', students: 52, status: 'في إجازة', joinDate: '2022-11-20' },
];

interface ManagerTeachersProps {
  onEnterTeacherPortal?: () => void;
}

const ManagerTeachers: React.FC<ManagerTeachersProps> = ({ onEnterTeacherPortal }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [teachers, setTeachers] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    fullName: '',
    specialty: 'حفظ ومراجعة',
    status: 'نشط'
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_teachers');
    if (saved) {
      setTeachers(JSON.parse(saved));
    } else {
      setTeachers(INITIAL_TEACHERS);
      localStorage.setItem('afaq_teachers', JSON.stringify(INITIAL_TEACHERS));
    }
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setFormData({ fullName: '', specialty: 'حفظ ومراجعة', status: 'نشط' });
    setShowModal(true);
  };

  const openEditModal = (teacher: any) => {
    setEditingId(teacher.id);
    setFormData({
      fullName: teacher.name,
      specialty: teacher.specialty,
      status: teacher.status
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updated;

    if (editingId) {
      updated = teachers.map(t => 
        t.id === editingId 
          ? { ...t, name: formData.fullName, specialty: formData.specialty, status: formData.status } 
          : t
      );
    } else {
      const newTeacher = {
        id: 'T' + Math.floor(Math.random() * 1000),
        name: formData.fullName,
        specialty: formData.specialty,
        students: 0,
        status: formData.status,
        joinDate: new Date().toISOString().split('T')[0]
      };
      updated = [newTeacher, ...teachers];
    }

    setTeachers(updated);
    localStorage.setItem('afaq_teachers', JSON.stringify(updated));
    setShowModal(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المعلم نهائياً؟')) {
      const updated = teachers.filter(t => t.id !== id);
      setTeachers(updated);
      localStorage.setItem('afaq_teachers', JSON.stringify(updated));
    }
  };

  const inputClass = "w-full px-5 py-3 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium";
  const labelClass = "block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest";

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">إدارة المعلمين</h2>
          <p className="text-slate-500 text-sm">تحكم كامل في بيانات الكادر التعليمي وصلاحيات الدخول</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 flex items-center gap-2"
        >
          <span>➕</span> إضافة معلم جديد
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase">المعلم</th>
              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase text-center">الحالة</th>
              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase text-center">المعاينة</th>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {teachers.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-bold">{t.name.charAt(0)}</div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700">{t.name}</span>
                      <span className="text-[10px] text-slate-400 font-medium">{t.specialty}</span>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${t.status === 'نشط' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                    {t.status}
                  </span>
                </td>
                <td className="px-6 py-5 text-center">
                  <button 
                    onClick={onEnterTeacherPortal}
                    className="px-4 py-2 bg-slate-100 text-slate-600 rounded-xl text-[10px] font-black hover:bg-emerald-600 hover:text-white transition-all active:scale-95 border border-transparent hover:border-emerald-200"
                  >
                    دخول كمعلم 👤
                  </button>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openEditModal(t)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100" title="تعديل">📝</button>
                    <button onClick={() => handleDelete(t.id)} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100" title="حذف">🗑️</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[40px] shadow-2xl animate-scaleIn">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">{editingId ? 'تعديل بيانات المعلم' : 'إضافة معلم جديد'}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div>
                <label className={labelClass}>الاسم الكامل</label>
                <input required value={formData.fullName} type="text" className={inputClass} onChange={(e) => setFormData({...formData, fullName: e.target.value})} />
              </div>
              <div>
                <label className={labelClass}>التخصص</label>
                <select className={inputClass} value={formData.specialty} onChange={(e) => setFormData({...formData, specialty: e.target.value})}>
                  <option>حفظ ومراجعة</option>
                  <option>تجويد وقراءات</option>
                  <option>تفسير</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>الحالة</label>
                <select className={inputClass} value={formData.status} onChange={(e) => setFormData({...formData, status: e.target.value})}>
                  <option value="نشط">نشط</option>
                  <option value="في إجازة">في إجازة</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition-all">حفظ البيانات</button>
                <button type="button" onClick={() => setShowModal(false)} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-200">إلغاء</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerTeachers;

import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const TeacherDashboard: React.FC = () => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  // نموذج التسميع
  const [recitationForm, setRecitationForm] = useState({
    hifdh: { surah: 'البقرة', from: 1, to: 10, grade: 'ممتاز' },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, grade: 'ممتاز' },
    review: { surah: 'النبأ', from: 1, to: 40, grade: 'ممتاز' },
    notes: ''
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) {
      setStudents(JSON.parse(saved));
    } else {
      const initial = [
        { id: 'S101', name: 'يوسف العتيبي', task: 'سورة البقرة (1-20)', status: 'بانتظار التسميع', lastGrade: '-', circle: 'حلقة الريان' },
        { id: 'S102', name: 'عمر خالد', task: 'سورة آل عمران (45-60)', status: 'تم التسميع', lastGrade: 'امتياز', circle: 'حلقة الريان' },
        { id: 'S103', name: 'فهد الرشيد', task: 'سورة الملك (كاملة)', status: 'متأخر', lastGrade: 'جيد جداً', circle: 'حلقة الريان' },
      ];
      setStudents(initial);
      localStorage.setItem('afaq_students', JSON.stringify(initial));
    }
  }, []);

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    // محاولة جلب آخر ورد مسجل للطالب إذا وجد
    setRecitationForm({
      hifdh: { surah: student.plan?.hifdh?.surah || 'البقرة', from: 1, to: 10, grade: 'ممتاز' },
      tathbeet: { surah: student.plan?.tathbeet?.surah || 'الفاتحة', from: 1, to: 7, grade: 'ممتاز' },
      review: { surah: student.plan?.review?.surah || 'النبأ', from: 1, to: 40, grade: 'ممتاز' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const updatedStudents = students.map(s => {
      if (s.id === selectedStudent.id) {
        return {
          ...s,
          status: 'تم التسميع',
          lastGrade: recitationForm.hifdh.grade,
          lastRecitationDate: new Date().toISOString(),
          history: [
            ...(s.history || []),
            { date: new Date().toISOString(), ...recitationForm }
          ]
        };
      }
      return s;
    });

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowRecitationModal(false);
    alert(`تم تسجيل تسميع الطالب ${selectedStudent.name} بنجاح ✅`);
  };

  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold";
  const labelClass = "block text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest";

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Header Info */}
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-700 rounded-3xl flex items-center justify-center text-3xl font-bold shadow-inner">
            👨‍🏫
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">حلقة اليوم</h2>
            <p className="text-slate-500 text-sm">لديك {students.filter(s => s.status !== 'تم التسميع').length} طلاب بانتظار التسميع</p>
          </div>
        </div>
        <div className="flex gap-4">
          <div className="text-center px-6 py-3 bg-slate-50 rounded-2xl border">
            <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase tracking-wider">المنجزين</p>
            <p className="text-xl font-black text-emerald-600">{students.filter(s => s.status === 'تم التسميع').length} / {students.length}</p>
