import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const TeacherDashboard: React.FC = () => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  // نموذج التسميع
  const [recitationForm, setRecitationForm] = useState({
    hifdh: { surah: 'النبأ', from: 1, to: 10, grade: '10' },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, grade: '10' },
    review: { surah: 'النبأ', from: 1, to: 40, grade: '10' },
    notes: ''
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) {
      setStudents(JSON.parse(saved));
    } else {
      const initial = [
        { id: 'S101', name: 'يوسف العتيبي', task: 'سورة النبأ (1-40)', status: 'بانتظار التسميع', lastGrade: '-', circle: 'حلقة الريان' },
        { id: 'S102', name: 'عمر خالد', task: 'سورة آل عمران (45-60)', status: 'تم التسميع', lastGrade: '10', circle: 'حلقة الريان' },
        { id: 'S103', name: 'فهد الرشيد', task: 'سورة الملك (كاملة)', status: 'متأخر', lastGrade: '8', circle: 'حلقة الريان' },
      ];
      setStudents(initial);
      localStorage.setItem('afaq_students', JSON.stringify(initial));
    }
  }, []);

  // دالة لجلب السورة التالية في الترتيب
  const getNextSurah = (currentSurahName: string) => {
    const currentIndex = SURAHS.findIndex(s => s.name === currentSurahName);
    // إذا وجدنا السورة ولم تكن الأخيرة في القائمة (بناءً على الترتيب المختار)
    // هنا سننتقل للسورة التي تسبقها في الترتيب (مثل النبأ 78 -> المرسلات 77) كما طلب المستخدم
    if (currentIndex > 0) {
      return SURAHS[currentIndex - 1].name;
    }
    return currentSurahName; // ابقَ في نفس السورة إذا كانت الفاتحة
  };

  const openRecitation = (student: any) => {
    setSelectedStudent(student);

    // محاولة استخراج السورة من نص المهمة إذا لم تكن في الخطة
    let currentSurah = 'النبأ';
    if (student.plan?.hifdh?.surah) {
      currentSurah = student.plan.hifdh.surah;
    } else if (student.task) {
      const match = student.task.match(/سورة\s+([^\s(]+)/);
      if (match) currentSurah = match[1];
    }

    setRecitationForm({
      hifdh: { surah: currentSurah, from: 1, to: 10, grade: '10' },
      tathbeet: { surah: student.plan?.tathbeet?.surah || 'الفاتحة', from: 1, to: 7, grade: '10' },
      review: { surah: student.plan?.review?.surah || 'النبأ', from: 1, to: 40, grade: '10' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const isPassing = ['10', '9', '8'].includes(recitationForm.hifdh.grade);
    let nextSurah = recitationForm.hifdh.surah;
    let nextTask = selectedStudent.task;

    if (isPassing) {
      nextSurah = getNextSurah(recitationForm.hifdh.surah);
      nextTask = `سورة ${nextSurah} (بداية السورة)`;
    }

    const updatedStudents = students.map(s => {
      if (s.id === selectedStudent.id) {
        const needsRepeat = 
          recitationForm.hifdh.grade === 'يعاد' || 
          recitationForm.tathbeet.grade === 'يعاد' || 
          recitationForm.review.grade === 'يعاد';

        return {
          ...s,
          status: needsRepeat ? 'يحتاج إعادة' : 'تم التسميع',
          task: needsRepeat ? s.task : nextTask,
          lastGrade: recitationForm.hifdh.grade,
          lastRecitationDate: new Date().toISOString(),
          plan: {
            ...s.plan,
            hifdh: { surah: nextSurah, from: 1, to: 10 },
            lastUpdated: new Date().toISOString()
          },
          history: [
            ...(s.history || []),
            { date: new Date().toISOString(), ...recitationForm }
          ]
        };
      }
      return s;
    });

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowRecitationModal(false);

    const message = isPassing && nextSurah !== recitationForm.hifdh.surah 
      ? `تم الحفظ! انتقل الطالب تلقائياً إلى سورة ${nextSurah} 🎉`
      : `تم تسجيل تسميع الطالب ${selectedStudent.name} بنجاح ✅`;

    alert(message);
  };

  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold";
  const labelClass = "block text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest";

  const RatingButtons = ({ currentGrade, onSelect, colorClass = 'emerald' }: { currentGrade: string, onSelect: (g: string) => void, colorClass?: string }) => {
    const grades = ['10', '9', '8', 'يعاد'];
    const activeColor = colorClass === 'emerald' ? 'bg-emerald-600 border-emerald-600' : colorClass === 'blue' ? 'bg-blue-600 border-blue-600' : 'bg-purple-600 border-purple-600';
    const repeatActive = 'bg-red-600 border-red-600';
    const repeatBg = 'bg-red-50 text-red-600 border-red-100 hover:bg-red-100';

    return (
      <div className="flex gap-2">
        {grades.map(g => (
          <button 
            key={g}
            type="button"
            onClick={() => onSelect(g)}
            className={`flex-1 py-2.5 rounded-xl text-xs font-black transition-all border ${
              currentGrade === g 
                ? (g === 'يعاد' ? `${repeatActive} text-white shadow-md scale-105` : `${activeColor} text-white shadow-md scale-105`)
                : (g === 'يعاد' ? repeatBg : 'bg-slate-50 text-slate-500 border-slate-200 hover:bg-slate-100')
            }`}
          >
            {g === 'يعاد' ? 'يُعاد 🔄' : g}
          </button>
        ))}
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Header Info */}
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-700 rounded-3xl flex items-center justify-center text-3xl font-bold shadow-inner">
            👨‍🏫
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">حلقة اليوم</h2>
            <p className="text-slate-500 text-sm">لديك {students.filter(s => s.status !== 'تم التسميع').length} طلاب بانتظار التسميع</p>
          </div>
        </div>
        <div className="flex gap-4">
          <div className="text-center px-6 py-3 bg-slate-50 rounded-2xl border">
            <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase tracking-wider">المنجزين</p>
            <p className="text-xl font-black text-emerald-600">{students.filter(s => s.status === 'تم التسميع').length} / {students.length}</p>
          </div>
          <div className="text-center px-6 py-3 bg-slate-50 rounded-2xl border">
            <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase tracking-wider">الوقت المتبقي</p>
            <p className="text-xl font-black text-amber-500">45 د</p>
          </div>
        </div>
      </div>

      {/* Students List */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
          <h3 className="font-bold text-slate-800">كشف متابعة الحلقات</h3>
          <div className="flex gap-2">
            <button className="px-4 py-2 bg-emerald-600 text-white text-xs font-bold rounded-xl hover:bg-emerald-700 transition-colors">إرسال تقرير جماعي</button>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="text-xs text-slate-400 border-b">
                <th className="px-8 py-4 font-bold uppercase">الطالب</th>
