                  <div><label className={labelClass}>إلى آية</label><input type="number" className={inputClass} value={recitationForm.tathbeet.to} onChange={(e) => setRecitationForm({...recitationForm, tathbeet: {...recitationForm.tathbeet, to: parseInt(e.target.value) || 0}})} /></div>
                  <div className="md:col-span-4">
