                  <LineCounterBadge from={recitationForm.review.from} to={recitationForm.review.to} />
                </div>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                  <div className="md:col-span-2">
                    <label className={labelClass}>السورة</label>
                    <select className={inputClass} value={recitationForm.review.surah} onChange={(e) => setRecitationForm({...recitationForm, review: {...recitationForm.review, surah: e.target.value}})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                  </div>
                  <div><label className={labelClass}>من آية</label><input type="number" className={inputClass} value={recitationForm.review.from} onChange={(e) => setRecitationForm({...recitationForm, review: {...recitationForm.review, from: parseInt(e.target.value) || 0}})} /></div>
                  <div><label className={labelClass}>إلى آية</label><input type="number" className={inputClass} value={recitationForm.review.to} onChange={(e) => setRecitationForm({...recitationForm, review: {...recitationForm.review, to: parseInt(e.target.value) || 0}})} /></div>
                  <div className="md:col-span-4">
                    <RatingButtons currentGrade={recitationForm.review.grade} onSelect={(g) => setRecitationForm({...recitationForm, review: {...recitationForm.review, grade: g}})} colorClass="purple" />
                  </div>
                </div>
              </section>

              <div className="p-2">
                <label className={labelClass}>ملاحظات الأداء</label>
                <textarea className="w-full px-4 py-3 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs h-24 resize-none" placeholder="اكتب أي ملاحظات للمعلم أو ولي الأمر..." value={recitationForm.notes} onChange={(e) => setRecitationForm({...recitationForm, notes: e.target.value})}></textarea>
              </div>
            </div>

            <div className="p-8 border-t bg-slate-50 flex gap-4 shrink-0">
              <button onClick={saveRecitation} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95">
                💾 حفظ التسميع واحتساب الإنجاز
              </button>
              <button onClick={() => setShowRecitationModal(false)} className="px-10 py-4 bg-white border border-slate-200 text-slate-500 rounded-2xl font-bold">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

