import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const TeacherDashboard: React.FC = () => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  const [recitationForm, setRecitationForm] = useState({
    hifdh: { surah: 'النبأ', from: 1, to: 10, grade: '10' },
    tathbeet: { surah: 'النازعات', from: 1, to: 10, grade: '10' },
    review: { surah: 'النبأ', from: 1, to: 40, grade: '10' },
    notes: ''
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) {
      setStudents(JSON.parse(saved));
    } else {
      const initial = [
        { id: 'S101', name: 'يوسف العتيبي', task: 'سورة النبأ (1-10)', status: 'بانتظار التسميع', lastGrade: '-', circle: 'حلقة الريان' },
        { id: 'S102', name: 'عمر خالد', task: 'سورة الناس (1-6)', status: 'تم التسميع', lastGrade: '10', circle: 'حلقة الريان' },
        { id: 'S103', name: 'فهد الرشيد', task: 'سورة الملك (1-10)', status: 'متأخر', lastGrade: '8', circle: 'حلقة الريان' },
      ];
      setStudents(initial);
      localStorage.setItem('afaq_students', JSON.stringify(initial));
    }
  }, []);

  // دالة ذكية لحساب الورد القادم مع دعم الترتيب العكسي (من الناس للفاتحة)
  const calculateNextAssignment = (currentAssignment: any) => {
    const { surah, from, to, grade } = currentAssignment;
    const isPassing = ['10', '9', '8'].includes(grade);

    if (!isPassing) return { surah, from, to }; 

    const currentSurahObj = SURAHS.find(s => s.name === surah);
    const versesCount = currentSurahObj?.versesCount || 40;
    const amount = Math.max(1, to - from + 1); // المقدار المعتاد للطالب

    let nextFrom = to + 1;
    let nextTo = to + amount;

    // إذا انتهينا من السورة الحالية
    if (nextFrom > versesCount) {
      const currentIndex = SURAHS.findIndex(s => s.name === surah);
      // الترتيب العكسي: ننتقل للسورة التي تسبقها في ترتيب المصحف (Index - 1)
      if (currentIndex > 0) {
        const nextSurahName = SURAHS[currentIndex - 1].name;
        const nextSurahObj = SURAHS[currentIndex - 1];
        let finalNextTo = amount;
        if (finalNextTo > nextSurahObj.versesCount) finalNextTo = nextSurahObj.versesCount;

        return { surah: nextSurahName, from: 1, to: finalNextTo };
      }
      return { surah, from: 1, to: amount }; // إعادة البداية إذا وصل للفاتحة
    }

    if (nextTo > versesCount) nextTo = versesCount;

    return { surah, from: nextFrom, to: nextTo };
  };

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: { 
        surah: student.plan?.hifdh?.surah || 'النبأ', 
        from: student.plan?.hifdh?.from || 1, 
        to: student.plan?.hifdh?.to || 10, 
        grade: '10' 
      },
      tathbeet: { 
        surah: student.plan?.tathbeet?.surah || 'النازعات', 
        from: student.plan?.tathbeet?.from || 1, 
        to: student.plan?.tathbeet?.to || 10, 
        grade: '10' 
      },
      review: { 
        surah: student.plan?.review?.surah || 'النبأ', 
        from: student.plan?.review?.from || 1, 
        to: student.plan?.review?.to || 40, 
        grade: '10' 
      },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const hifdhLines = Math.max(0, recitationForm.hifdh.to - recitationForm.hifdh.from + 1);
    const tathbeetLines = Math.max(0, recitationForm.tathbeet.to - recitationForm.tathbeet.from + 1);
    const reviewLines = Math.max(0, recitationForm.review.to - recitationForm.review.from + 1);

    const nextHifdh = calculateNextAssignment(recitationForm.hifdh);
    const nextTathbeet = calculateNextAssignment(recitationForm.tathbeet);
    const nextReview = calculateNextAssignment(recitationForm.review);

    const updatedStudents = students.map(s => {
      if (s.id === selectedStudent.id) {
        const needsRepeat = 
          recitationForm.hifdh.grade === 'يعاد' || 
          recitationForm.tathbeet.grade === 'يعاد' || 
          recitationForm.review.grade === 'يعاد';

        return {
          ...s,
          status: needsRepeat ? 'يحتاج إعادة' : 'تم التسميع',
          task: needsRepeat ? s.task : `سورة ${nextHifdh.surah} (${nextHifdh.from}-${nextHifdh.to})`,
          lastGrade: recitationForm.hifdh.grade,
          lastRecitationDate: new Date().toISOString(),
          plan: {
            ...s.plan,
            hifdh: nextHifdh,
            tathbeet: nextTathbeet,
            review: nextReview,
            lastUpdated: new Date().toISOString()
          },
          history: [
            ...(s.history || []),
            { 
              date: new Date().toISOString(), 
              ...recitationForm,
              summary: { hifdhLines, tathbeetLines, reviewLines }
            }
          ]
        };
      }
      return s;
    });

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowRecitationModal(false);

    alert(`تم الحفظ والترحيل التلقائي بنجاح!
━━━━━━━━━━━━━━━━━━
✨ إحصائيات الإنجاز:
- حفظ: ${hifdhLines} أسطر
- تثبيت: ${tathbeetLines} أسطر
- مراجعة: ${reviewLines} أسطر
━━━━━━━━━━━━━━━━━━
🚀 الورد القادم: سورة ${nextHifdh.surah}`);
  };

  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold transition-all";
  const labelClass = "block text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest";

  const LineCounterBadge = ({ from, to }: { from: number, to: number }) => {
    const count = Math.max(0, to - from + 1);
    return (
      <div className="flex items-center gap-1 bg-slate-900 text-white px-3 py-1 rounded-lg text-[10px] font-black shadow-lg">
        <span>{count}</span>
        <span className="opacity-60 italic">سطر</span>
      </div>
    );
  };

  const RatingButtons = ({ currentGrade, onSelect, colorClass = 'emerald' }: { currentGrade: string, onSelect: (g: string) => void, colorClass?: string }) => {
    const grades = ['10', '9', '8', 'يعاد'];
    const activeColors: Record<string, string> = {
      emerald: 'bg-emerald-600 border-emerald-600',
      blue: 'bg-blue-600 border-blue-600',
      purple: 'bg-purple-600 border-purple-600'
    };

    return (
      <div className="flex gap-2">
        {grades.map(g => (
          <button 
            key={g}
            type="button"
            onClick={() => onSelect(g)}
            className={`flex-1 py-2.5 rounded-xl text-xs font-black transition-all border ${
              currentGrade === g 
                ? (g === 'يعاد' ? 'bg-red-600 border-red-600 text-white shadow-lg scale-105' : `${activeColors[colorClass]} text-white shadow-lg scale-105`)
                : (g === 'يعاد' ? 'bg-red-50 text-red-600 border-red-100' : 'bg-slate-50 text-slate-500 border-slate-200')
            }`}
          >
            {g === 'يعاد' ? 'يُعاد 🔄' : g}
          </button>
        ))}
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Header Info */}
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-700 rounded-3xl flex items-center justify-center text-3xl font-bold shadow-inner">👨‍🏫</div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">حلقة السلمان</h2>
            <p className="text-slate-500 text-sm">نظام ترحيل آلي: من الناس إلى الفاتحة</p>
          </div>
        </div>
        <div className="flex gap-4">
          <div className="text-center px-6 py-3 bg-emerald-600 text-white rounded-2xl shadow-lg shadow-emerald-100">
            <p className="text-[10px] font-bold mb-1 opacity-70 uppercase tracking-wider">المنجزين</p>
            <p className="text-xl font-black">{students.filter(s => s.status === 'تم التسميع').length} / {students.length}</p>
          </div>
        </div>
      </div>

      {/* Students List */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b flex items-center justify-between bg-slate-50/50">
          <h3 className="font-bold text-slate-800">كشف تسميع الطلاب</h3>
          <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full">الترحيل الذكي مفعل ✅</span>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="text-xs text-slate-400 border-b">
                <th className="px-8 py-4 font-bold uppercase">اسم الطالب</th>
                <th className="px-6 py-4 font-bold uppercase">الورد المطلوب</th>
                <th className="px-6 py-4 font-bold uppercase">الحالة</th>
                <th className="px-6 py-4 font-bold uppercase">آخر تقييم</th>
                <th className="px-8 py-4 font-bold uppercase text-left">الإجراء</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {students.map((student, i) => (
                <tr key={i} className="group hover:bg-slate-50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center text-xs font-bold border border-slate-100">
                        {student.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-700 text-sm">{student.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    <span className="text-xs font-bold text-slate-500">{student.task || '-'}</span>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${
                      student.status === 'تم التسميع' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'
                    }`}>
                      {student.status}
                    </span>
                  </td>
                  <td className="px-6 py-5 font-black text-slate-800">{student.lastGrade || '-'}</td>
                  <td className="px-8 py-5 text-left">
                    <button onClick={() => openRecitation(student)} className="px-4 py-2 bg-emerald-50 text-emerald-700 text-xs font-black rounded-xl hover:bg-emerald-600 hover:text-white transition-all border border-emerald-100">
                      تسجيل التسميع 🎙️
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Recitation Modal */}
      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden animate-scaleIn max-h-[95vh] flex flex-col">
            <div className="p-8 border-b bg-emerald-900 text-white flex justify-between items-center shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center text-2xl">📖</div>
                <div>
                  <h3 className="text-xl font-bold">تسجيل إنجاز: {selectedStudent?.name}</h3>
                  <p className="text-xs text-emerald-200">الترحيل التلقائي سيعمل بناءً على تقييمك</p>
