import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

const INITIAL_STUDENTS = [
  { 
    id: 'S101', 
    name: 'يوسف العتيبي', 
    memorized: '15 جزء', 
    teacher: 'د. عبد الله الماجد', 
    circle: 'حلقة الريان', 
    status: 'بانتظار التسميع',
    progress: 85,
    idNumber: '1092837465',
    plan: {
      hifdh: { surah: 'النبأ', from: 1, to: 10, grade: '10' },
      tathbeet: { surah: 'النازعات', from: 1, to: 10, grade: '10' },
      review: { surah: 'النبأ', from: 1, to: 40, grade: '10' },
      lastUpdated: new Date().toISOString()
    }
  },
];

const ManagerStudents: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showRecitationModal, setShowRecitationModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [availableCircles, setAvailableCircles] = useState<any[]>([]);

  // نموذج تسجيل التسميع (حصري للمدير)
  const [recitationForm, setRecitationForm] = useState({
    hifdh: { surah: 'النبأ', from: 1, to: 10, grade: '10' },
    tathbeet: { surah: 'النازعات', from: 1, to: 10, grade: '10' },
    review: { surah: 'النبأ', from: 1, to: 40, grade: '10' },
    notes: ''
  });

  const [formData, setFormData] = useState({
    fullName: '', selectedCircle: '', idNumber: '', birthDate: '', nationality: 'سعودي'
  });

  useEffect(() => {
    const savedStudents = localStorage.getItem('afaq_students');
    if (savedStudents) {
      setStudents(JSON.parse(savedStudents));
    } else {
      setStudents(INITIAL_STUDENTS);
      localStorage.setItem('afaq_students', JSON.stringify(INITIAL_STUDENTS));
    }

    const savedCircles = localStorage.getItem('afaq_circles');
    if (savedCircles) {
      setAvailableCircles(JSON.parse(savedCircles));
    }
  }, []);

  // دالة الترحيل التلقائي (من الناس للفاتحة)
  const calculateNextAssignment = (currentAssignment: any) => {
    const { surah, from, to, grade } = currentAssignment;
    const isPassing = ['10', '9', '8'].includes(grade);
    if (!isPassing) return { surah, from, to }; 

    const currentSurahObj = SURAHS.find(s => s.name === surah);
    const versesCount = currentSurahObj?.versesCount || 40;
    const amount = Math.max(1, to - from + 1);

    let nextFrom = to + 1;
    let nextTo = to + amount;

    if (nextFrom > versesCount) {
      const currentIndex = SURAHS.findIndex(s => s.name === surah);
      if (currentIndex > 0) {
        const nextSurahObj = SURAHS[currentIndex - 1];
        return { surah: nextSurahObj.name, from: 1, to: Math.min(amount, nextSurahObj.versesCount) };
      }
      return { surah, from: 1, to: amount }; 
    }
    if (nextTo > versesCount) nextTo = versesCount;
    return { surah, from: nextFrom, to: nextTo };
  };

  const handleOpenRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh || { surah: 'النبأ', from: 1, to: 10, grade: '10' },
      tathbeet: student.plan?.tathbeet || { surah: 'النازعات', from: 1, to: 10, grade: '10' },
      review: student.plan?.review || { surah: 'النبأ', from: 1, to: 40, grade: '10' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const hifdhLines = Math.max(0, recitationForm.hifdh.to - recitationForm.hifdh.from + 1);
    const tathbeetLines = Math.max(0, recitationForm.tathbeet.to - recitationForm.tathbeet.from + 1);
    const reviewLines = Math.max(0, recitationForm.review.to - recitationForm.review.from + 1);

    const nextHifdh = calculateNextAssignment(recitationForm.hifdh);
    const nextTathbeet = calculateNextAssignment(recitationForm.tathbeet);
    const nextReview = calculateNextAssignment(recitationForm.review);

    const updatedStudents = students.map(s => {
      if (s.id === selectedStudent.id) {
        return {
          ...s,
          status: 'تم التسميع',
          lastGrade: recitationForm.hifdh.grade,
          plan: {
            hifdh: nextHifdh,
            tathbeet: nextTathbeet,
            review: nextReview,
            lastUpdated: new Date().toISOString()
          },
          history: [...(s.history || []), { date: new Date().toISOString(), summary: { hifdhLines, tathbeetLines, reviewLines } }]
        };
      }
      return s;
    });

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowRecitationModal(false);
    alert(`تم الترحيل بنجاح! إجمالي الأسطر: ${hifdhLines + tathbeetLines + reviewLines}`);
  };

  const labelClass = "block text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest";
  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500";

  return (
    <div className="space-y-6 animate-fadeIn pb-10">
      <div className="flex justify-between items-center bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">شؤون الطلاب (المدير)</h2>
          <p className="text-slate-500 text-sm">تسجيل التسميع والترحيل التلقائي خاص بصلاحياتك</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-emerald-100">➕ طالب جديد</button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b">
            <tr className="text-xs text-slate-400 font-bold">
              <th className="px-8 py-4">الطالب</th>
              <th className="px-6 py-4">الحلقة</th>
              <th className="px-6 py-4">الحالة</th>
              <th className="px-8 py-4 text-left">إجراءات المدير</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {students.map((st) => (
              <tr key={st.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-8 py-4 font-bold text-slate-700">{st.name}</td>
                <td className="px-6 py-4 text-xs font-bold text-slate-500">{st.circle}</td>
                <td className="px-6 py-4">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${st.status === 'تم التسميع' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{st.status}</span>
                </td>
                <td className="px-8 py-4 text-left">
                  <button onClick={() => handleOpenRecitation(st)} className="bg-emerald-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-md hover:scale-105 transition-transform">
                    تسجيل تسميع 🎙️
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* مودال تسجيل التسميع (حصري للمدير) */}
      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-8 bg-emerald-900 text-white flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold">تسميع: {selectedStudent?.name}</h3>
                <p className="text-xs text-emerald-200">صلاحية المدير: الترحيل التلقائي مفعل</p>
              </div>
              <button onClick={() => setShowRecitationModal(false)}>✕</button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {['hifdh', 'tathbeet', 'review'].map((type: any) => (
                <section key={type} className="bg-slate-50 p-6 rounded-3xl border border-slate-200">
                  <div className="flex justify-between items-center mb-4 border-b border-slate-200 pb-3">
                    <h4 className="font-black text-slate-800 uppercase text-xs">
                      {type === 'hifdh' ? '✨ الحفظ الجديد' : type === 'tathbeet' ? '📌 التثبيت' : '🔄 المراجعة'}
                    </h4>
                    <span className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-[10px] font-black">
                      {Math.max(0, recitationForm[type].to - recitationForm[type].from + 1)} أسطر
                    </span>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="md:col-span-2">
                      <label className={labelClass}>السورة</label>
                      <select className={inputClass} value={recitationForm[type].surah} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], surah: e.target.value}})}>
                        {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                      </select>
                    </div>
                    <div><label className={labelClass}>من</label><input type="number" className={inputClass} value={recitationForm[type].from} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], from: parseInt(e.target.value)}})} /></div>
                    <div><label className={labelClass}>إلى</label><input type="number" className={inputClass} value={recitationForm[type].to} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], to: parseInt(e.target.value)}})} /></div>
                    <div className="md:col-span-4 flex gap-2">
                      {['10', '9', '8', 'يعاد'].map(g => (
                        <button key={g} onClick={() => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], grade: g}})} className={`flex-1 py-2 rounded-xl text-xs font-black border transition-all ${recitationForm[type].grade === g ? 'bg-emerald-600 text-white' : 'bg-white text-slate-400'}`}>
                          {g === 'يعاد' ? '🔄 يُعاد' : g}
                        </button>
                      ))}
                    </div>
                  </div>
                </section>
              ))}
            </div>
            <div className="p-8 border-t bg-slate-50">
              <button onClick={saveRecitation} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl">تأكيد التسميع والترحيل التلقائي</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

