import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const TeacherDashboard: React.FC = () => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  const [recitationForm, setRecitationForm] = useState({
    hifdh: { surah: 'النبأ', from: 1, to: 10, grade: '10' },
    tathbeet: { surah: 'النازعات', from: 1, to: 10, grade: '10' },
    review: { surah: 'النبأ', from: 1, to: 40, grade: '10' },
    notes: ''
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) {
      setStudents(JSON.parse(saved));
    }
  }, []);

  const calculateNextAssignment = (currentAssignment: any) => {
    const { surah, from, to, grade } = currentAssignment;
    const isPassing = ['10', '9', '8'].includes(grade);
    if (!isPassing) return { surah, from, to }; 

    const currentSurahObj = SURAHS.find(s => s.name === surah);
    const versesCount = currentSurahObj?.versesCount || 40;
    const amount = Math.max(1, to - from + 1);

    let nextFrom = to + 1;
    let nextTo = to + amount;

    if (nextFrom > versesCount) {
      const currentIndex = SURAHS.findIndex(s => s.name === surah);
      if (currentIndex > 0) {
        const nextSurahObj = SURAHS[currentIndex - 1];
        return { surah: nextSurahObj.name, from: 1, to: Math.min(amount, nextSurahObj.versesCount) };
      }
      return { surah, from: 1, to: amount }; 
    }
    if (nextTo > versesCount) nextTo = versesCount;
    return { surah, from: nextFrom, to: nextTo };
  };

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh || { surah: 'النبأ', from: 1, to: 10, grade: '10' },
      tathbeet: student.plan?.tathbeet || { surah: 'النازعات', from: 1, to: 10, grade: '10' },
      review: student.plan?.review || { surah: 'النبأ', from: 1, to: 40, grade: '10' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const hifdhLines = Math.max(0, recitationForm.hifdh.to - recitationForm.hifdh.from + 1);
    const tathbeetLines = Math.max(0, recitationForm.tathbeet.to - recitationForm.tathbeet.from + 1);
    const reviewLines = Math.max(0, recitationForm.review.to - recitationForm.review.from + 1);

    const nextHifdh = calculateNextAssignment(recitationForm.hifdh);
    const nextTathbeet = calculateNextAssignment(recitationForm.tathbeet);
    const nextReview = calculateNextAssignment(recitationForm.review);

    const updatedStudents = students.map(s => {
      if (s.id === selectedStudent.id) {
        return {
          ...s,
          status: 'تم التسميع',
          lastGrade: recitationForm.hifdh.grade,
          task: `سورة ${nextHifdh.surah} (${nextHifdh.from}-${nextHifdh.to})`,
          plan: {
            hifdh: nextHifdh,
            tathbeet: nextTathbeet,
            review: nextReview,
            lastUpdated: new Date().toISOString()
          },
          history: [...(s.history || []), { date: new Date().toISOString(), summary: { hifdhLines, tathbeetLines, reviewLines } }]
        };
      }
      return s;
    });

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowRecitationModal(false);
    alert(`تم الحفظ بنجاح!\nإجمالي الأسطر المنجزة: ${hifdhLines + tathbeetLines + reviewLines}`);
  };

  const labelClass = "block text-[9px] font-black text-slate-400 mb-1 uppercase tracking-widest";
  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500";

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-700 rounded-3xl flex items-center justify-center text-3xl font-bold shadow-inner">👨‍🏫</div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">متابعة طلاب الحلقة</h2>
            <p className="text-slate-500 text-sm">نظام رصد الإنجاز المباشر وحساب الأسطر</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b">
            <tr className="text-xs text-slate-400 font-bold uppercase">
              <th className="px-8 py-4">اسم الطالب</th>
              <th className="px-6 py-4">المقدار الحالي</th>
              <th className="px-6 py-4">الحالة</th>
              <th className="px-8 py-4 text-left">الإجراء</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {students.map((student, i) => (
              <tr key={i} className="hover:bg-slate-50 transition-colors">
                <td className="px-8 py-5 font-bold text-slate-700">{student.name}</td>
                <td className="px-6 py-5 text-xs text-slate-500">{student.task || '-'}</td>
                <td className="px-6 py-5">
                   <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${student.status === 'تم التسميع' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'}`}>{student.status}</span>
                </td>
                <td className="px-8 py-5 text-left">
                  <button onClick={() => openRecitation(student)} className="bg-emerald-600 text-white px-5 py-2 rounded-xl text-xs font-black shadow-md">تسجيل تسميع 🎙️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-8 bg-emerald-900 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold">رصد إنجاز: {selectedStudent?.name}</h3>
              <button onClick={() => setShowRecitationModal(false)}>✕</button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              {['hifdh', 'tathbeet', 'review'].map((type: any) => (
                <section key={type} className="bg-slate-50 p-6 rounded-3xl border border-slate-200">
                  <div className="flex justify-between items-center mb-4">
                    <h4 className="font-black text-slate-800 text-xs">
                      {type === 'hifdh' ? '✨ الحفظ الجديد' : type === 'tathbeet' ? '📌 التثبيت' : '🔄 المراجعة'}
                    </h4>
                    <div className="bg-slate-900 text-white px-3 py-1 rounded-lg text-[10px] font-black">
                      {Math.max(0, recitationForm[type].to - recitationForm[type].from + 1)} سطر
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="md:col-span-2">
                      <label className={labelClass}>السورة</label>
                      <select className={inputClass} value={recitationForm[type].surah} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], surah: e.target.value}})}>
                        {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                      </select>
                    </div>
                    <div><label className={labelClass}>من آية</label><input type="number" className={inputClass} value={recitationForm[type].from} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], from: parseInt(e.target.value) || 0}})} /></div>
                    <div><label className={labelClass}>إلى آية</label><input type="number" className={inputClass} value={recitationForm[type].to} onChange={(e) => setRecitationForm({...recitationForm, [type]: {...recitationForm[type], to: parseInt(e.target.value) || 0}})} /></div>
                  </div>
                </section>
              ))}
            </div>
            <div className="p-8 bg-slate-50 border-t">
              <button onClick={saveRecitation} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl">حفظ وإحصاء أسطر الإنجاز 💾</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TeacherDashboard;

