      fullName: teacher.name,
      specialty: teacher.specialty,
      status: teacher.status,
      username: teacher.username || '',
      password: teacher.password || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updated;

