              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase text-center">الحالة</th>
              <th className="px-6 py-5 text-xs font-bold text-slate-400 uppercase text-center">المعاينة</th>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {teachers.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
