              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>التخصص</label>
                  <select className={inputClass} value={formData.specialty} onChange={(e) => setFormData({...formData, specialty: e.target.value})}>
                    <option>حفظ ومراجعة</option>
                    <option>تجويد وقراءات</option>
                    <option>تفسير</option>
                  </select>
