import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIAssistance = async (prompt: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // ترقية الموديل لأداء أفضل في التفسير
      contents: prompt,
      config: {
        systemInstruction: "أنت 'معلم آفاق الذكي'. خبير في علوم القرآن، التفسير، وأحكام التجويد. أسلوبك هادئ، مشجع، ويستخدم مفردات عربية فصيحة وبسيطة. إذا سألك الطالب عن آية، قدم له تفسيراً ميسراً وربطاً تربوياً لحياته اليومية.",
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 2000 } // إتاحة فرصة للموديل للتفكير في الإجابة التربوية
      }
    });
    return response.text || "عذراً، أحتاج لبرهة من التفكير. هل يمكنك إعادة سؤالك؟";
  } catch (error) {
    console.error("AI Error:", error);
    return "حدث خطأ في الاتصال بالمعلم الذكي، يرجى المحاولة لاحقاً.";
  }
};

export const getRecitationFeedback = async (audioBase64: string, verseText: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: audioBase64, mimeType: 'audio/pcm;rate=16000' } },
          { text: `كخبير تجويد، حلل قراءة الطالب لهذه الآية: "${verseText}". ركز على مخارج الحروف والمدود الطبيعية.` }
        ]
      }
    });
    return response.text || "لم أتمكن من تحليل الصوت بدقة هذه المرة.";
  } catch (error) {
    console.error("Audio Analysis Error:", error);
    return "خطأ في معالجة تحليل الصوت.";
  }
};

