import React, { useState, useRef, useEffect } from 'react';
import { getAIAssistance } from '../services/geminiService';
import { ChatMessage } from '../types';

const AIConsultant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'أهلاً بك يا بني. أنا معلمك الذكي في منصة آفاق. كيف يمكنني مساعدتك اليوم في فهم أو حفظ القرآن الكريم؟ أنا هنا للإجابة على تساؤلاتك التربوية وعلوم القرآن.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const responseText = await getAIAssistance(input);
    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-[56px] shadow-2xl border border-slate-100 overflow-hidden animate-fadeIn">
      <div className="p-10 bg-emerald-800 text-white flex items-center gap-6 shadow-xl relative overflow-hidden">
        <div className="relative z-10 w-16 h-16 bg-emerald-100 rounded-[24px] flex items-center justify-center text-4xl shadow-inner border border-emerald-500/20">🤖</div>
        <div className="relative z-10">
          <h2 className="text-3xl font-black quran-font">المعلم الذكي</h2>
          <p className="text-emerald-200 text-sm font-bold opacity-80 uppercase tracking-widest mt-1">مساعدك الرقمي لعلوم القرآن والتجويد</p>
        </div>
        {/* Decorative circle */}
        <div className="absolute top-[-20%] right-[-5%] w-40 h-40 bg-white/5 rounded-full blur-3xl"></div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-10 space-y-10 bg-slate-50/50">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-fadeIn`}>
            <div className={`max-w-[75%] p-8 rounded-[40px] text-xl leading-relaxed shadow-lg ${
              msg.role === 'user' 
              ? 'bg-gradient-to-br from-emerald-600 to-emerald-700 text-white rounded-br-none' 
              : 'bg-white text-slate-800 rounded-bl-none border border-slate-100'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-end">
            <div className="bg-white p-6 rounded-[32px] rounded-bl-none border border-slate-100 shadow-sm flex gap-2">
              <div className="w-3 h-3 bg-emerald-400 rounded-full animate-bounce"></div>
              <div className="w-3 h-3 bg-emerald-400 rounded-full animate-bounce delay-100"></div>
              <div className="w-3 h-3 bg-emerald-400 rounded-full animate-bounce delay-200"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-10 bg-white border-t border-slate-100 shadow-2xl">
        <div className="flex items-center gap-5 bg-slate-50 p-3 rounded-[32px] border-2 border-slate-100 focus-within:border-emerald-500 focus-within:bg-white transition-all duration-300">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="اسأل المعلم عن التفسير، التجويد، أو معاني الآيات..."
            className="flex-1 bg-transparent border-none focus:ring-0 px-6 py-4 text-xl font-bold text-slate-800 placeholder:text-slate-300"
          />
          <button 
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="bg-emerald-600 text-white w-16 h-16 rounded-[24px] flex items-center justify-center text-2xl hover:bg-emerald-700 disabled:bg-slate-200 disabled:text-slate-400 transition-all shadow-lg active:scale-90"
          >
            ✈️
          </button>
        </div>
        <div className="flex items-center justify-center gap-2 mt-6">
            <span className="text-[11px] font-black text-slate-300 uppercase tracking-widest">Afaq AI Engine • Powered by Gemini 3 Pro</span>
        </div>
      </div>
    </div>
  );
};

export default AIConsultant;

