    notes: ''
  });

  const [formData, setFormData] = useState({
    fullName: '', selectedCircle: '', idNumber: '', birthDate: '', nationality: 'سعودي'
  });

  useEffect(() => {
    const savedStudents = localStorage.getItem('afaq_students');
    if (savedStudents) {
      setStudents(JSON.parse(savedStudents));
    } else {
      setStudents(INITIAL_STUDENTS);
      localStorage.setItem('afaq_students', JSON.stringify(INITIAL_STUDENTS));
    }

    const savedCircles = localStorage.getItem('afaq_circles');
    if (savedCircles) {
