import { SURAHS } from '../constants';

const ManagerStudents: React.FC = () => {
  const [showRecitationModal, setShowRecitationModal] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [students, setStudents] = useState<any[]>([]);

  const [recitationForm, setRecitationForm] = useState<any>({
    hifdh: { surah: 'النبأ', grade: '10' },
    tathbeet: { surah: 'النازعات', grade: '10' },
    review: { surah: 'النبأ', grade: '10' }
  });

  useEffect(() => {
    const saved = localStorage.getItem('afaq_students');
    if (saved) setStudents(JSON.parse(saved));
  }, []);

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh || { surah: 'النبأ', grade: '10' },
      tathbeet: student.plan?.tathbeet || { surah: 'النازعات', grade: '10' },
      review: student.plan?.review || { surah: 'النبأ', grade: '10' }
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const updated = students.map(s => 
      s.id === selectedStudent.id ? { ...s, status: 'تم التسميع' } : s
    );
    setStudents(updated);
    localStorage.setItem('afaq_students', JSON.stringify(updated));
    setShowRecitationModal(false);
    alert('تم رصد التسميع من قبل الإدارة');
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1 tracking-widest";
  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500/20 transition-all";

  return (
    <div className="space-y-5 animate-fadeIn">
      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100">
        <h2 className="text-lg font-black text-slate-800 quran-font">شؤون الطلاب</h2>
        <p className="text-slate-500 text-[10px]">رصد التسميع والتحكم في النتائج</p>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right text-xs">
          <thead className="bg-slate-50 border-b">
            <tr className="text-[10px] text-slate-400 font-black uppercase">
              <th className="px-6 py-3">الطالب</th>
              <th className="px-6 py-3">الحالة</th>
              <th className="px-6 py-3 text-left">إجراءات</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {students.map((st) => (
              <tr key={st.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-3 font-bold text-slate-700">{st.name}</td>
                <td className="px-6 py-3">
                   <span className={`px-2 py-0.5 rounded-full text-[9px] font-black ${st.status === 'تم التسميع' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>{st.status}</span>
                </td>
                <td className="px-6 py-3 text-left">
                  <button onClick={() => openRecitation(st)} className="bg-emerald-800 text-white px-3 py-1 rounded-lg text-[9px] font-black">🎙️ رصد</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/30 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-scaleIn">
            <div className="p-6 bg-emerald-950 text-white flex justify-between items-center">
              <h3 className="text-base font-black quran-font">رصد: {selectedStudent?.name}</h3>
              <button onClick={() => setShowRecitationModal(false)}>✕</button>
            </div>

            <div className="p-6 space-y-3">
              {['hifdh', 'tathbeet', 'review'].map((id) => (
                <div key={id} className="flex gap-3 items-end p-3 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="flex-1">
                    <label className={labelClass}>{id === 'hifdh' ? 'الحفظ' : id === 'tathbeet' ? 'التثبيت' : 'المراجعة'}</label>
                    <select className={inputClass} value={recitationForm[id].surah} onChange={(e) => setRecitationForm({...recitationForm, [id]: {...recitationForm[id], surah: e.target.value}})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                  </div>
                  <div className="flex gap-1">
                    {['10', '9', 'يعاد'].map(g => (
                      <button 
                        key={g} 
                        onClick={() => setRecitationForm({...recitationForm, [id]: {...recitationForm[id], grade: g}})}
                        className={`w-8 h-8 rounded-lg text-[9px] font-black border transition-all ${recitationForm[id].grade === g ? 'bg-emerald-800 text-white' : 'bg-white text-slate-400 border-slate-200'}`}
                      >
                        {g === 'يعاد' ? '🔄' : g}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 bg-slate-50 border-t flex gap-3">
              <button onClick={saveRecitation} className="flex-1 py-3 bg-emerald-900 text-white rounded-xl text-xs font-black">تأكيد الحفظ</button>
              <button onClick={() => setShowRecitationModal(false)} className="px-6 py-3 bg-white text-slate-400 border border-slate-200 rounded-xl text-xs font-bold">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerStudents;

import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const ManagerStudents: React.FC = () => {
  const [showRecitationModal, setShowRecitationModal] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [circles, setCircles] = useState<any[]>([]);

  const [recitationForm, setRecitationForm] = useState<any>({
    hifdh: { surah: 'النبأ', grade: '10' },
    tathbeet: { surah: 'النازعات', grade: '10' },
    review: { surah: 'النبأ', grade: '10' }
  });

  const [studentForm, setStudentForm] = useState({
    name: '',
    circle: '',
    idNumber: '',
    birthDate: '',
    status: 'نشط'
  });

  useEffect(() => {
    const savedStudents = localStorage.getItem('afaq_students');
    const savedCircles = localStorage.getItem('afaq_circles');

    if (savedStudents) setStudents(JSON.parse(savedStudents));
    if (savedCircles) setCircles(JSON.parse(savedCircles));
  }, []);

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh || { surah: 'النبأ', grade: '10' },
      tathbeet: student.plan?.tathbeet || { surah: 'النازعات', grade: '10' },
      review: student.plan?.review || { surah: 'النبأ', grade: '10' }
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const updated = students.map(s => 
      s.id === selectedStudent.id ? { ...s, status: 'تم التسميع' } : s
    );
    setStudents(updated);
    localStorage.setItem('afaq_students', JSON.stringify(updated));
    setShowRecitationModal(false);
    alert('تم رصد التسميع من قبل الإدارة');
  };

  const handleAddStudent = (e: React.FormEvent) => {
    e.preventDefault();
    const newStudent = {
      id: Date.now().toString(),
      name: studentForm.name,
      circle: studentForm.circle,
      idNumber: studentForm.idNumber,
      birthDate: studentForm.birthDate,
      status: studentForm.status,
      progress: 0,
      joinDate: new Date().toISOString().split('T')[0]
    };

    const updatedStudents = [newStudent, ...students];
    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    setShowAddModal(false);
    setStudentForm({ name: '', circle: '', idNumber: '', birthDate: '', status: 'نشط' });
  };

  const handleDeleteStudent = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الطالب نهائياً؟')) {
      const updated = students.filter(s => s.id !== id);
      setStudents(updated);
      localStorage.setItem('afaq_students', JSON.stringify(updated));
    }
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1 tracking-widest uppercase";
  const inputClass = "w-full px-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 transition-all";

  return (
    <div className="space-y-6 animate-fadeIn pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-black text-slate-800 quran-font">شؤون الطلاب</h2>
          <p className="text-slate-500 text-sm font-medium">إدارة ملفات الطلاب الجدد وتوزيعهم على الحلقات</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100 flex items-center gap-2 active:scale-95"
        >
          <span>➕</span> إضافة طالب جديد
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5">اسم الطالب</th>
              <th className="px-6 py-5">الحلقة</th>
              <th className="px-6 py-5 text-center">الحالة</th>
              <th className="px-8 py-5 text-left">الإجراءات</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {students.length > 0 ? students.map((st) => (
              <tr key={st.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-black">
                      {st.name.charAt(0)}
                    </div>
                    <div>
                      <p className="font-bold text-slate-800">{st.name}</p>
                      <p className="text-[10px] text-slate-400 font-medium">{st.idNumber || 'بدون رقم هوية'}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <span className="text-xs font-bold text-slate-500">{st.circle || 'غير محدد'}</span>
                </td>
                <td className="px-6 py-5 text-center">
                   <span className={`px-3 py-1 rounded-full text-[10px] font-black ${st.status === 'نشط' || st.status === 'تم التسميع' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
                     {st.status}
                   </span>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openRecitation(st)} className="bg-emerald-800 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-md hover:scale-105 transition-transform">
                      رصد 🎙️
                    </button>
                    <button onClick={() => handleDeleteStudent(st.id)} className="p-2 hover:bg-red-50 text-red-500 rounded-xl transition-all border border-transparent hover:border-red-100">
                      🗑️
                    </button>
                  </div>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan={4} className="py-20 text-center">
                  <div className="text-4xl mb-4 grayscale opacity-20">👥</div>
                  <p className="text-slate-400 font-bold">لا يوجد طلاب مسجلين حالياً</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* نموذج إضافة طالب جديد */}
      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[48px] shadow-2xl animate-scaleIn overflow-hidden">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-xl font-black text-slate-800 quran-font">تسجيل طالب جديد</h3>
                <p className="text-xs text-slate-400 font-bold mt-1 uppercase tracking-widest">إنشاء سجل أكاديمي جديد</p>
              </div>
              <button onClick={() => setShowAddModal(false)} className="w-10 h-10 flex items-center justify-center rounded-2xl hover:bg-slate-200 text-slate-400 transition-all font-bold">✕</button>
            </div>

            <form onSubmit={handleAddStudent} className="p-8 space-y-5">
              <div>
                <label className={labelClass}>الاسم الرباعي للطالب</label>
                <input required type="text" className={inputClass} value={studentForm.name} onChange={(e) => setStudentForm({...studentForm, name: e.target.value})} placeholder="أدخل اسم الطالب الكامل" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>رقم الهوية / الإقامة</label>
                  <input required type="text" className={inputClass} value={studentForm.idNumber} onChange={(e) => setStudentForm({...studentForm, idNumber: e.target.value})} placeholder="10xxxxxxxx" />
                </div>
                <div>
                  <label className={labelClass}>تاريخ الميلاد</label>
                  <input required type="date" className={inputClass} value={studentForm.birthDate} onChange={(e) => setStudentForm({...studentForm, birthDate: e.target.value})} />
                </div>
              </div>

              <div>
                <label className={labelClass}>تحديد الحلقة</label>
                <select required className={inputClass} value={studentForm.circle} onChange={(e) => setStudentForm({...studentForm, circle: e.target.value})}>
                  <option value="">اختر حلقة الطالب...</option>
                  {circles.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                </select>
              </div>

              <div className="flex gap-4 pt-6">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-5 rounded-[24px] font-black shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95">
                  تأكيد تسجيل الطالب
                </button>
                <button type="button" onClick={() => setShowAddModal(false)} className="px-10 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-bold hover:bg-slate-200 transition-all">إلغاء</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* نموذج رصد التسميع */}
      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/30 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-scaleIn">
            <div className="p-6 bg-emerald-950 text-white flex justify-between items-center">
              <h3 className="text-base font-black quran-font">رصد: {selectedStudent?.name}</h3>
              <button onClick={() => setShowRecitationModal(false)}>✕</button>
            </div>

            <div className="p-6 space-y-3">
              {['hifdh', 'tathbeet', 'review'].map((id) => (
                <div key={id} className="flex gap-3 items-end p-3 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="flex-1">
                    <label className={labelClass}>{id === 'hifdh' ? 'الحفظ' : id === 'tathbeet' ? 'التثبيت' : 'المراجعة'}</label>
                    <select className={inputClass.replace('py-3', 'py-2')} value={recitationForm[id].surah} onChange={(e) => setRecitationForm({...recitationForm, [id]: {...recitationForm[id], surah: e.target.value}})}>
                      {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                    </select>
                  </div>
                  <div className="flex gap-1">
                    {['10', '9', 'يعاد'].map(g => (
                      <button 
                        key={g} 
                        onClick={() => setRecitationForm({...recitationForm, [id]: {...recitationForm[id], grade: g}})}
                        className={`w-8 h-8 rounded-lg text-[9px] font-black border transition-all ${recitationForm[id].grade === g ? 'bg-emerald-800 text-white' : 'bg-white text-slate-400 border-slate-200'}`}
                      >
                        {g === 'يعاد' ? '🔄' : g}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 bg-slate-50 border-t flex gap-3">
              <button onClick={saveRecitation} className="flex-1 py-3 bg-emerald-900 text-white rounded-xl text-xs font-black">تأكيد الحفظ</button>
              <button onClick={() => setShowRecitationModal(false)} className="px-6 py-3 bg-white text-slate-400 border border-slate-200 rounded-xl text-xs font-bold">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerStudents;

