    alert('تم رصد التسميع وتحديث حالة الطالب بنجاح');
  };

  const handleAddStudent = (e: React.FormEvent) => {
    e.preventDefault();
    const newStudent = {
      id: Date.now().toString(),
      name: studentForm.name,
      circle: studentForm.circle,
