    const updatedStudents = [newStudent, ...students];
    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));

    // تحديث عدد الطلاب في الحلقة المختارة
    const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');
    const updatedCircles = savedCircles.map((c: any) => 
      c.name === studentForm.circle ? { ...c, students: (c.students || 0) + 1 } : c
    );
    localStorage.setItem('afaq_circles', JSON.stringify(updatedCircles));

    window.dispatchEvent(new Event('storage')); // إرسال إشارة لجميع الواجهات بالتحديث
    setShowAddModal(false);
    setStudentForm({ name: '', circle: '', idNumber: '', birthDate: '', status: 'نشط' });
