import React, { useState, useEffect } from 'react';

const ManagerTeachers: React.FC<{ onEnterTeacherPortal?: () => void }> = ({ onEnterTeacherPortal }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [teachers, setTeachers] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    fullName: '',
    specialty: 'حفظ ومراجعة',
    status: 'نشط',
    username: '',
    password: ''
  });

  useEffect(() => {
    const loadTeachers = () => {
      const saved = localStorage.getItem('afaq_teachers');
      if (saved) setTeachers(JSON.parse(saved));
    };
    loadTeachers();
    window.addEventListener('storage', loadTeachers);
    return () => window.removeEventListener('storage', loadTeachers);
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setFormData({ fullName: '', specialty: 'حفظ ومراجعة', status: 'نشط', username: '', password: '' });
    setShowModal(true);
  };

  const openEditModal = (teacher: any) => {
    setEditingId(teacher.id);
    setFormData({ fullName: teacher.name, specialty: teacher.specialty, status: teacher.status, username: teacher.username || '', password: teacher.password || '' });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updated;

    if (editingId) {
      updated = teachers.map(t => t.id === editingId ? { ...t, name: formData.fullName, specialty: formData.specialty, status: formData.status, username: formData.username, password: formData.password } : t);
    } else {
      const newTeacher = {
        id: 'T' + Date.now(),
        name: formData.fullName,
        specialty: formData.specialty,
        students: 0,
        status: formData.status,
        joinDate: new Date().toISOString().split('T')[0],
        username: formData.username,
        password: formData.password
      };
      updated = [newTeacher, ...teachers];
    }

    setTeachers(updated);
    localStorage.setItem('afaq_teachers', JSON.stringify(updated));
    window.dispatchEvent(new Event('storage'));
    setShowModal(false);
    alert('تم حفظ بيانات المعلم بنجاح');
  };

  const handleDelete = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المعلم نهائياً؟')) {
      const updated = teachers.filter(t => t.id !== id);
      setTeachers(updated);
      localStorage.setItem('afaq_teachers', JSON.stringify(updated));
      window.dispatchEvent(new Event('storage'));
    }
  };

  const inputClass = "w-full px-5 py-3 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm font-medium";
  const labelClass = "block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest";

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="flex justify-between items-center bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">إدارة المعلمين</h2>
          <p className="text-slate-500 text-sm">تحكم كامل في الكادر التعليمي وصلاحية الدخول المباشر</p>
        </div>
        <button onClick={openAddModal} className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all shadow-xl flex items-center gap-2"><span>➕</span> إضافة معلم جديد</button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b">
            <tr>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">المعلم</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase text-center">الحالة</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {teachers.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-bold">{t.name.charAt(0)}</div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700">{t.name}</span>
                      <span className="text-[10px] text-slate-400 font-medium tracking-wider">@{t.username}</span>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${t.status === 'نشط' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>{t.status}</span>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button 
                      onClick={() => onEnterTeacherPortal && onEnterTeacherPortal()} 
                      className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black hover:bg-emerald-700 transition-all flex items-center gap-2 shadow-md"
                      title="دخول لواجهة المعلم"
                    >
                      دخول 🚪
                    </button>
                    <button onClick={() => openEditModal(t)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100">📝</button>
                    <button onClick={() => handleDelete(t.id)} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100">🗑️</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[40px] shadow-2xl animate-scaleIn">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">{editingId ? 'تعديل بيانات المعلم' : 'إضافة معلم جديد'}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className={labelClass}>الاسم الكامل</label>
                <input required value={formData.fullName} type="text" className={inputClass} onChange={(e) => setFormData({...formData, fullName: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4 pt-4 border-t">
                <div>
                  <label className={labelClass}>اسم المستخدم</label>
                  <input required value={formData.username} type="text" className={inputClass} onChange={(e) => setFormData({...formData, username: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>كلمة المرور</label>
                  <input required value={formData.password} type="text" className={inputClass} onChange={(e) => setFormData({...formData, password: e.target.value})} />
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black shadow-lg">حفظ البيانات</button>
                <button type="button" onClick={() => setShowModal(false)} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold">إلغاء</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerTeachers;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
