import TeacherSessions from './components/TeacherSessions';
import TeacherCurriculum from './components/TeacherCurriculum';
import QuranReader from './components/QuranReader';
import AIConsultant from './components/AIConsultant';
import { UserRole } from './types';

const INITIAL_TEACHERS = [
  { id: 'T1', name: 'د. عبد الله الماجد', specialty: 'تجويد وقراءات', students: 45, status: 'نشط', joinDate: '2023-01-10', username: 'majed', password: '123' },
  { id: 'T2', name: 'أ. سارة المنصور', specialty: 'حفظ ومراجعة', students: 38, status: 'نشط', joinDate: '2023-03-15', username: 'sara', password: '123' },
];

const INITIAL_CIRCLES = [
  { id: 'C1', name: 'حلقة الريان', teacher: 'د. عبد الله الماجد', time: 'بعد العصر', days: 'الأحد - الثلاثاء', students: 2, max: 15 },
  { id: 'C2', name: 'حلقة الفردوس', teacher: 'أ. سارة المنصور', time: 'بعد المغرب', days: 'يومياً', students: 1, max: 10 },
];

const INITIAL_STUDENTS = [
  { id: '1', name: 'يوسف العتيبي', circle: 'حلقة الريان', idNumber: '1098765432', birthDate: '2010-05-15', status: 'نشط', progress: 85 },
  { id: '2', name: 'عمر بكر', circle: 'حلقة الريان', idNumber: '1122334455', birthDate: '2011-08-20', status: 'نشط', progress: 40 },
  { id: '3', name: 'سارة خالد', circle: 'حلقة الفردوس', idNumber: '1155667788', birthDate: '2012-02-10', status: 'نشط', progress: 65 },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [isManagerShadowing, setIsManagerShadowing] = useState(false);
  const [shadowedTeacher, setShadowedTeacher] = useState<any>(null);

  useEffect(() => {
    if (!localStorage.getItem('afaq_teachers')) {
      localStorage.setItem('afaq_teachers', JSON.stringify(INITIAL_TEACHERS));
    }
    if (!localStorage.getItem('afaq_circles')) {
      localStorage.setItem('afaq_circles', JSON.stringify(INITIAL_CIRCLES));
    }
    if (!localStorage.getItem('afaq_students')) {
      localStorage.setItem('afaq_students', JSON.stringify(INITIAL_STUDENTS));
    }
  }, []);

  const handleRoleSelection = (role: UserRole) => {
    setUserRole(role);
    setActiveTab('dashboard');
    setIsManagerShadowing(false);
    setShadowedTeacher(null);
  };

  const enterTeacherPortalAsManager = (teacher: any) => {
    setUserRole('teacher');
    setActiveTab('dashboard');
    setIsManagerShadowing(true);
    setShadowedTeacher(teacher);
  };

  const exitTeacherPortalToManager = () => {
    setUserRole('manager');
    setActiveTab('teachers'); 
    setIsManagerShadowing(false);
    setShadowedTeacher(null);
  };

  const handleLogout = () => {
    setUserRole(null);
    setIsManagerShadowing(false);
    setShadowedTeacher(null);
  };

  if (!userRole) {
    return <LandingPage onSelectRole={handleRoleSelection} />;
  }

  const renderManagerContent = () => {
    switch (activeTab) {
      case 'dashboard': return <ManagerDashboard />;
      case 'teachers': return <ManagerTeachers onEnterTeacherPortal={enterTeacherPortalAsManager} />;
      case 'circles': return <ManagerCircles />;
      case 'students_all': return <ManagerStudents />;
      case 'reports': return <ManagerReports />;
      default: return <ManagerDashboard />;
    }
  };

  const renderTeacherContent = () => {
    // تمرير بيانات المعلم الحالي (سواء كان دخوله حقيقياً أو محاكاة من المدير)
    const currentTeacherName = shadowedTeacher ? shadowedTeacher.name : 'د. عبد الله الماجد';

    switch (activeTab) {
      case 'dashboard': return <TeacherDashboard teacherName={currentTeacherName} />;
      case 'my_students': return <TeacherStudents teacherName={currentTeacherName} />;
      case 'sessions': return <TeacherSessions teacherName={currentTeacherName} />;
      case 'curriculum': return <TeacherCurriculum />;
      default: return <TeacherDashboard teacherName={currentTeacherName} />;
    }
  };

  const renderStudentContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard />;
      case 'quran': return <QuranReader />;
      case 'assistant': return <AIConsultant />;
      case 'progress':
        return (
          <div className="bg-white p-12 rounded-[40px] shadow-sm border border-slate-100 text-center space-y-6 animate-fadeIn">
            <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto text-5xl">🏆</div>
            <h2 className="text-2xl font-bold text-slate-800">سجل الإنجازات</h2>
            <p className="text-slate-500 max-w-md mx-auto">هنا ستجد الأوسمة والشهادات التي حصلت عليها خلال رحلة الحفظ المباركة في منصة آفاق.</p>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 pt-12">
              {[{ title: 'بداية مباركة', icon: '✨' }, { title: 'حفظ الجزء 30', icon: '📜' }, { title: 'أسبوع متواصل', icon: '🔥' }, { title: 'تجويد ممتاز', icon: '🔊' }].map((badge, i) => (
                <div key={i} className="flex flex-col items-center gap-4 group">
                  <div className="w-20 h-20 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl opacity-50 grayscale group-hover:grayscale-0 group-hover:opacity-100 transition-all cursor-help relative">🔒</div>
                  <span className="text-sm font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{badge.title}</span>
                </div>
              ))}
            </div>
          </div>
        );
      default: return <Dashboard />;
    }
  };

  const renderContent = () => {
    if (userRole === 'manager') return renderManagerContent();
    if (userRole === 'teacher') return renderTeacherContent();
    return renderStudentContent();
  };

  return (
    <div className="relative h-screen overflow-hidden flex flex-col">
      {isManagerShadowing && (
        <div className="bg-emerald-950 text-white px-8 py-3 flex items-center justify-between z-[60] shadow-xl animate-fadeIn border-b border-emerald-800">
          <div className="flex items-center gap-4">
            <span className="animate-pulse flex h-3 w-3 rounded-full bg-amber-400"></span>
            <p className="text-sm font-bold">وضع المحاكاة: أنت تتصفح الآن بصلاحية المعلم <span className="text-amber-400">({shadowedTeacher?.name})</span></p>
          </div>
          <button onClick={exitTeacherPortalToManager} className="bg-amber-500 hover:bg-amber-400 text-emerald-950 px-6 py-2 rounded-xl text-xs font-black transition-all flex items-center gap-2 shadow-lg">↩ العودة لبوابة المدير</button>
        </div>
      )}

      <div className="flex-1 overflow-hidden">
        <Layout activeTab={activeTab} setActiveTab={setActiveTab} userRole={userRole} setUserRole={setUserRole}>
          <div className="relative h-full">
            <button onClick={handleLogout} className="fixed bottom-8 left-8 bg-white/90 backdrop-blur-sm border border-slate-200 text-slate-400 hover:text-red-500 px-4 py-2 rounded-xl text-[10px] font-bold shadow-sm transition-all z-50 flex items-center gap-2 print:hidden"><span>🚪</span> تبديل الحساب / خروج</button>
            {renderContent()}
          </div>
        </Layout>
      </div>
    </div>
  );
};

export default App;

