import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

interface TeacherDashboardProps {
  teacherName?: string;
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ teacherName }) => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  const [recitationForm, setRecitationForm] = useState<any>({
    hifdh: { surah: 'النبأ', grade: '10' },
    tathbeet: { surah: 'النازعات', grade: '10' },
    review: { surah: 'النبأ', grade: '10' },
    notes: ''
  });

  useEffect(() => {
    const savedStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

    // فلترة الحلقات التابعة لهذا المعلم
    const teacherCircles = savedCircles
      .filter((c: any) => c.teacher === teacherName)
      .map((c: any) => c.name);

    // عرض فقط الطلاب التابعين لحلقات هذا المعلم
    const filteredStudents = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
    setStudents(filteredStudents);
  }, [teacherName]);

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh || { surah: 'النبأ', grade: '10' },
      tathbeet: student.plan?.tathbeet || { surah: 'النازعات', grade: '10' },
      review: student.plan?.review || { surah: 'النبأ', grade: '10' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => {
      if (s.id === selectedStudent.id) {
        return {
          ...s,
          status: 'تم التسميع',
          lastGrade: recitationForm.hifdh.grade,
          history: [...(s.history || []), { 
            date: new Date().toISOString(), 
            summary: recitationForm 
          }]
        };
      }
      return s;
    });

    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowRecitationModal(false);
    alert(`تم حفظ التسميع للطالب ${selectedStudent.name} بنجاح!`);
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest";
  const inputClass = "w-full px-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all";

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl font-bold">👨‍🏫</div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800 quran-font">لوحة المعلم: {teacherName}</h2>
            <p className="text-slate-500 text-sm font-medium">مرحباً بك، لديك {students.length} طالب بانتظار التسميع اليوم</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right text-sm">
          <thead className="bg-slate-50 border-b">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5">اسم الطالب</th>
              <th className="px-6 py-5">الحلقة</th>
              <th className="px-6 py-5 text-center">الحالة</th>
              <th className="px-8 py-5 text-left">الإجراء</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {students.length > 0 ? students.map((student, i) => (
              <tr key={i} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-5 font-bold text-slate-700">{student.name}</td>
                <td className="px-6 py-5">
                   <span className="text-xs text-slate-400 font-medium">{student.circle}</span>
                </td>
                <td className="px-6 py-5 text-center">
                   <span className={`px-3 py-1 rounded-full text-[9px] font-black ${student.status === 'تم التسميع' ? 'bg-emerald-50 text-emerald-700' : 'bg-slate-50 text-slate-500'}`}>{student.status}</span>
                </td>
                <td className="px-8 py-5 text-left">
                  <button onClick={() => openRecitation(student)} className="bg-emerald-600 text-white px-5 py-2 rounded-xl text-[10px] font-black shadow-md hover:bg-emerald-700 transition-all">رصد التسميع 🎙️</button>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan={4} className="py-20 text-center text-slate-400">لا يوجد طلاب مسجلين في حلقاتك حالياً</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg rounded-[32px] shadow-2xl overflow-hidden animate-scaleIn">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center text-right">
              <h3 className="text-base font-black quran-font">تسميع: {selectedStudent?.name}</h3>
              <button onClick={() => setShowRecitationModal(false)} className="text-xl">✕</button>
            </div>

            <div className="p-6 space-y-4">
              {[
                { id: 'hifdh', title: 'الحفظ الجديد', color: 'emerald' },
                { id: 'tathbeet', title: 'التثبيت', color: 'blue' },
                { id: 'review', title: 'المراجعة', color: 'purple' }
              ].map((section: any) => (
                <div key={section.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <h4 className={`text-xs font-black text-${section.color}-700 mb-3`}>{section.title}</h4>
                  <div className="flex gap-3 items-end">
                    <div className="flex-1">
                      <label className={labelClass}>السورة</label>
                      <select className={inputClass} value={recitationForm[section.id].surah} onChange={(e) => setRecitationForm({...recitationForm, [section.id]: {...recitationForm[section.id], surah: e.target.value}})}>
                        {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                      </select>
                    </div>
                    <div className="flex gap-1">
                      {['10', '9', 'يعاد'].map(g => (
                        <button 
                          key={g} 
                          onClick={() => setRecitationForm({...recitationForm, [section.id]: {...recitationForm[section.id], grade: g}})}
                          className={`w-8 h-8 rounded-lg text-[9px] font-black border transition-all ${recitationForm[section.id].grade === g ? `bg-${section.color}-600 text-white border-${section.color}-600` : 'bg-white text-slate-400 border-slate-200'}`}
                        >
                          {g === 'يعاد' ? '🔄' : g}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 border-t flex gap-3">
              <button onClick={saveRecitation} className="flex-1 py-3 bg-emerald-600 text-white rounded-xl text-xs font-black shadow-lg">حفظ التسميع</button>
              <button onClick={() => setShowRecitationModal(false)} className="px-6 py-3 bg-slate-100 text-slate-500 rounded-xl text-xs font-bold">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

