      const teacherCircles = savedCircles
        .filter((c: any) => c.teacher === teacherName)
        .map((c: any) => c.name);

      // فلترة الطلاب التابعين لهذه الحلقات
      const filtered = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
      setStudents(filtered);
    };

    loadFilteredData();
    window.addEventListener('storage', loadFilteredData);
    return () => window.removeEventListener('storage', loadFilteredData);
  }, [teacherName]);

  const openPlanModal = (student: any) => {
    setSelectedStudent(student);
    if (student.plan) {
      setPlanForm(student.plan);
    } else {
      setPlanForm({
        hifdh: { surah: 'البقرة', from: 1, to: 5, lines: 5 },
        tathbeet: { surah: 'الفاتحة', from: 1, to: 7, lines: 7 },
        review: { surah: 'النبأ', from: 1, to: 20, lines: 20 },
        lastUpdated: new Date().toISOString()
      });
    }
    setShowPlanModal(true);
  };

  const savePlan = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => 
      s.id === selectedStudent.id ? { ...s, plan: { ...planForm, lastUpdated: new Date().toISOString() } } : s
    );
    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowPlanModal(false);
    alert(`تم تحديث خطة الطالب ${selectedStudent.name} بنجاح`);
  };

  const renderPlanSection = (type: 'hifdh' | 'tathbeet' | 'review', title: string, icon: string, color: string) => (
    <div className={`p-6 bg-${color}-50/50 rounded-3xl border border-${color}-100`}>
      <div className="flex items-center gap-2 mb-4">
        <span className="text-xl">{icon}</span>
        <h4 className={`font-black text-${color}-800`}>{title}</h4>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div>
          <label className="block text-[10px] font-bold text-slate-400 mb-2 uppercase tracking-widest">السورة</label>
          <select 
            className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-emerald-500 text-sm font-bold"
            value={planForm[type].surah}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], surah: e.target.value}})}
          >
            {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-[10px] font-bold text-slate-400 mb-2 uppercase tracking-widest">من آية</label>
          <input 
            type="number" 
            className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-emerald-500 text-sm font-bold"
            value={planForm[type].from}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], from: parseInt(e.target.value)}})}
          />
        </div>
        <div>
          <label className="block text-[10px] font-bold text-slate-400 mb-2 uppercase tracking-widest">إلى آية</label>
          <input 
            type="number" 
            className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-emerald-500 text-sm font-bold"
            value={planForm[type].to}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], to: parseInt(e.target.value)}})}
          />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <h2 className="text-2xl font-bold text-slate-800 quran-font">قائمة طلابي</h2>
        <p className="text-slate-500 text-sm font-medium">إدارة خطط الحفظ والمتابعة الفردية للطلاب التابعين لك</p>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5">الطالب</th>
              <th className="px-6 py-5">الحلقة</th>
              <th className="px-6 py-5 text-center">تقدم الحفظ</th>
              <th className="px-8 py-5 text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {students.length > 0 ? students.map((s) => (
              <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-bold">
                      {s.name.charAt(0)}
                    </div>
                    <span className="font-bold text-slate-700">{s.name}</span>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <span className="text-xs text-slate-400 font-medium">{s.circle}</span>
                </td>
                <td className="px-6 py-5 text-center">
                  <div className="flex items-center justify-center gap-3">
                    <div className="w-24 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                      <div className="h-full bg-emerald-500" style={{width: `${s.progress}%`}}></div>
                    </div>
                    <span className="text-[10px] font-black text-slate-400">{s.progress}%</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-left">
                  <button 
                    onClick={() => openPlanModal(s)}
                    className="bg-slate-900 text-white px-5 py-2 rounded-xl text-[10px] font-black hover:bg-emerald-700 transition-all shadow-md"
                  >
                    تعديل الخطة 📅
                  </button>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan={4} className="py-20 text-center text-slate-400 font-bold italic">
                  لا يوجد طلاب مسجلين في حلقاتك حالياً.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showPlanModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[48px] shadow-2xl animate-scaleIn overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-xl font-black text-slate-800 quran-font">تعديل الخطة الدراسية</h3>
                <p className="text-xs text-slate-400 font-bold mt-1">تحديد ورد الطالب: {selectedStudent?.name}</p>
              </div>
              <button onClick={() => setShowPlanModal(false)} className="text-slate-400 font-bold text-xl">✕</button>
            </div>

            <div className="p-8 space-y-6 overflow-y-auto">
              {renderPlanSection('hifdh', 'الحفظ الجديد', '✨', 'emerald')}
              {renderPlanSection('tathbeet', 'التثبيت والمراجعة الصغرى', '📌', 'blue')}
              {renderPlanSection('review', 'المراجعة الكبرى', '🔄', 'purple')}
            </div>

            <div className="p-8 bg-slate-50 border-t flex gap-4">
              <button 
                onClick={savePlan}
                className="flex-1 bg-emerald-600 text-white py-5 rounded-[24px] font-black shadow-xl hover:bg-emerald-700 transition-all"
              >
                حفظ الخطة وتنبيه الطالب
              </button>
              <button 
                onClick={() => setShowPlanModal(false)}
                className="px-10 py-5 bg-white border border-slate-200 text-slate-500 rounded-[24px] font-bold"
              >
                إلغاء
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

