            onClick={exitTeacherPortalToManager}
            className="bg-amber-500 hover:bg-amber-400 text-emerald-950 px-8 py-2.5 rounded-2xl text-xs font-black transition-all flex items-center gap-2 shadow-lg shadow-amber-900/20 active:scale-95"
          >
            ↩ العودة لإدارة آفاق
          </button>
        </div>
      )}

      <div className="flex-1 overflow-hidden">
        <Layout 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
