    setTeachers(updated);
    localStorage.setItem('afaq_teachers', JSON.stringify(updated));
    window.dispatchEvent(new Event('storage'));
    setShowModal(false);
    alert(editingId ? 'تم تحديث بيانات المعلم بنجاح' : 'تمت إضافة المعلم بنجاح');
  };

  const handleDelete = (id: string) => {
    const teacher = teachers.find(t => t.id === id);
    if (window.confirm(`⚠️ تحذير: هل أنت متأكد من حذف المعلم "${teacher?.name}" نهائياً؟ سيؤدي هذا لإغلاق حسابه ومنع دخوله.`)) {
      const updated = teachers.filter(t => t.id !== id);
      setTeachers(updated);
      localStorage.setItem('afaq_teachers', JSON.stringify(updated));
      window.dispatchEvent(new Event('storage'));
