  const labelClass = "block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest";

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="flex justify-between items-center bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 quran-font">إدارة المعلمين</h2>
          <p className="text-slate-500 text-sm">تحكم في الكادر التعليمي، بيانات الدخول، والحالات الأكاديمية</p>
        </div>
        <button onClick={openAddModal} className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all shadow-xl flex items-center gap-2 active:scale-95"><span>➕</span> إضافة معلم جديد</button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b">
            <tr>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">المعلم</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase text-center">التخصص</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase text-center">الحالة</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {teachers.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
