                    </div>
                  </div>
                </td>
                <td className="px-6 py-5 text-center">
                  <span className="text-xs font-medium text-slate-500">{t.specialty}</span>
                </td>
                <td className="px-6 py-5 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${t.status === 'نشط' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>{t.status}</span>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openEditModal(t)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100 shadow-sm flex items-center gap-2 text-xs font-bold">📝 تعديل</button>
                    <button onClick={() => handleDelete(t.id)} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100 shadow-sm flex items-center gap-2 text-xs font-bold">🗑️ حذف</button>
