      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[40px] shadow-2xl animate-scaleIn overflow-hidden">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">{editingId ? 'تعديل بيانات المعلم' : 'إضافة معلم جديد'}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-red-500 transition-colors">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2 sm:col-span-1">
                  <label className={labelClass}>الاسم الكامل</label>
                  <input required value={formData.fullName} type="text" className={inputClass} onChange={(e) => setFormData({...formData, fullName: e.target.value})} />
                </div>
                <div className="col-span-2 sm:col-span-1">
                  <label className={labelClass}>التخصص</label>
                  <select className={inputClass} value={formData.specialty} onChange={(e) => setFormData({...formData, specialty: e.target.value})}>
                    <option value="تجويد وقراءات">تجويد وقراءات</option>
                    <option value="حفظ ومراجعة">حفظ ومراجعة</option>
                    <option value="تفسير وعلوم قرآن">تفسير وعلوم قرآن</option>
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 pt-4 border-t">
                <div>
                  <label className={labelClass}>اسم المستخدم</label>
                  <input required value={formData.username} type="text" className={inputClass} onChange={(e) => setFormData({...formData, username: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>كلمة المرور</label>
                  <input required value={formData.password} type="text" className={inputClass} onChange={(e) => setFormData({...formData, password: e.target.value})} />
                </div>
              </div>
              <div>
                <label className={labelClass}>حالة المعلم</label>
                <select className={inputClass} value={formData.status} onChange={(e) => setFormData({...formData, status: e.target.value})}>
                  <option value="نشط">نشط</option>
                  <option value="إجازة">إجازة</option>
                  <option value="موقف">موقف</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition-all active:scale-95">حفظ البيانات</button>
