import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

const ManagerStudents: React.FC = () => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [circles, setCircles] = useState<any[]>([]);

  const [studentForm, setStudentForm] = useState({
    name: '',
    circle: '',
    idNumber: '',
    birthDate: '',
    status: 'نشط',
    parentPhone: ''
  });

  useEffect(() => {
    const loadData = () => {
      const savedStudents = localStorage.getItem('afaq_students');
      const savedCircles = localStorage.getItem('afaq_circles');

      if (savedStudents) setStudents(JSON.parse(savedStudents));
      if (savedCircles) setCircles(JSON.parse(savedCircles));
    };

    loadData();
    window.addEventListener('storage', loadData);
    return () => window.removeEventListener('storage', loadData);
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setStudentForm({ name: '', circle: '', idNumber: '', birthDate: '', status: 'نشط', parentPhone: '' });
    setShowAddModal(true);
  };

  const openEditModal = (student: any) => {
    setEditingId(student.id);
    setStudentForm({
      name: student.name,
      circle: student.circle || '',
      idNumber: student.idNumber || '',
      birthDate: student.birthDate || '',
      status: student.status || 'نشط',
      parentPhone: student.parentPhone || ''
    });
    setShowAddModal(true);
  };

  const handleSaveStudent = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedStudents;

    if (editingId) {
      // تعديل طالب موجود
      updatedStudents = students.map(s => 
        s.id === editingId ? { ...s, ...studentForm } : s
      );
    } else {
      // إضافة طالب جديد
      const newStudent = {
        id: Date.now().toString(),
        ...studentForm,
        progress: 0,
        joinDate: new Date().toISOString().split('T')[0]
      };
      updatedStudents = [newStudent, ...students];
    }

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));

    // إرسال إشارة للتحديث في باقي الواجهات
    window.dispatchEvent(new Event('storage'));
    setShowAddModal(false);
    alert(editingId ? 'تم تحديث بيانات الطالب بنجاح' : 'تم تسجيل الطالب بنجاح');
  };

  const handleDeleteStudent = (id: string) => {
    const student = students.find(s => s.id === id);
    if (window.confirm(`هل أنت متأكد من حذف الطالب "${student?.name}" نهائياً؟`)) {
      const updated = students.filter(s => s.id !== id);
      setStudents(updated);
      localStorage.setItem('afaq_students', JSON.stringify(updated));
      window.dispatchEvent(new Event('storage'));
    }
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1 tracking-widest uppercase";
  const inputClass = "w-full px-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all";

  return (
    <div className="space-y-6 animate-fadeIn pb-12 text-right">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-black text-slate-800 quran-font">شؤون الطلاب</h2>
          <p className="text-slate-500 text-sm font-medium">التحكم الكامل في سجلات وبيانات الطلاب</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all shadow-xl flex items-center gap-2 active:scale-95"
        >
          <span>➕</span> إضافة طالب جديد
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5">اسم الطالب</th>
              <th className="px-6 py-5">الحلقة</th>
              <th className="px-6 py-5 text-center">الحالة</th>
              <th className="px-8 py-5 text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {students.length > 0 ? students.map((st) => (
              <tr key={st.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-black">{st.name.charAt(0)}</div>
                    <div>
                      <p className="font-bold text-slate-800">{st.name}</p>
                      <p className="text-[10px] text-slate-400 font-medium">{st.idNumber}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <span className="text-xs font-bold text-slate-500">{st.circle || 'غير محدد'}</span>
                </td>
                <td className="px-6 py-5 text-center">
                   <span className={`px-3 py-1 rounded-full text-[10px] font-black ${st.status === 'نشط' || st.status === 'تم التسميع' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>{st.status}</span>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openEditModal(st)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100 shadow-sm flex items-center gap-2 text-xs font-bold">📝 تعديل</button>
                    <button onClick={() => handleDeleteStudent(st.id)} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100 shadow-sm flex items-center gap-2 text-xs font-bold">🗑️ حذف</button>
                  </div>
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan={4} className="py-20 text-center">
                  <p className="text-slate-400 font-bold">لا يوجد طلاب مسجلين حالياً</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-lg rounded-[48px] shadow-2xl animate-scaleIn overflow-hidden">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-xl font-black text-slate-800 quran-font">{editingId ? 'تعديل بيانات الطالب' : 'تسجيل طالب جديد'}</h3>
                <p className="text-xs text-slate-400 font-bold mt-1">أدخل البيانات الأساسية للطالب بدقة</p>
              </div>
              <button onClick={() => setShowAddModal(false)} className="text-slate-400 font-bold text-xl hover:text-red-500 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSaveStudent} className="p-8 space-y-5">
              <div>
                <label className={labelClass}>الاسم الكامل</label>
                <input required type="text" className={inputClass} value={studentForm.name} onChange={(e) => setStudentForm({...studentForm, name: e.target.value})} placeholder="أدخل اسم الطالب الكامل" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>رقم الهوية</label>
                  <input required type="text" className={inputClass} value={studentForm.idNumber} onChange={(e) => setStudentForm({...studentForm, idNumber: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>تاريخ الميلاد</label>
                  <input required type="date" className={inputClass} value={studentForm.birthDate} onChange={(e) => setStudentForm({...studentForm, birthDate: e.target.value})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>رقم ولي الأمر</label>
                  <input required type="tel" className={inputClass} value={studentForm.parentPhone} onChange={(e) => setStudentForm({...studentForm, parentPhone: e.target.value})} placeholder="05xxxxxxxx" />
                </div>
                <div>
                  <label className={labelClass}>الحلقة</label>
                  <select required className={inputClass} value={studentForm.circle} onChange={(e) => setStudentForm({...studentForm, circle: e.target.value})}>
                    <option value="">اختر الحلقة...</option>
                    {circles.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
              </div>
              <div>
                <label className={labelClass}>حالة الحساب</label>
                <select required className={inputClass} value={studentForm.status} onChange={(e) => setStudentForm({...studentForm, status: e.target.value})}>
                  <option value="نشط">نشط</option>
                  <option value="موقف">موقف</option>
                  <option value="خريج">خريج</option>
                </select>
              </div>
              <div className="flex gap-4 pt-6">
                <button type="submit" className="flex-1 bg-emerald-600 text-white py-5 rounded-[24px] font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95">حفظ البيانات</button>
                <button type="button" onClick={() => setShowAddModal(false)} className="px-10 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-bold hover:bg-slate-200 transition-all">إلغاء</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerStudents;

import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

interface TeacherStudentsProps {
  teacherName?: string;
}

const TeacherStudents: React.FC<TeacherStudentsProps> = ({ teacherName }) => {
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showPlanModal, setShowPlanModal] = useState(false);
  const [students, setStudents] = useState<any[]>([]);

  const [planForm, setPlanForm] = useState<StudyPlan>({
    hifdh: { surah: 'البقرة', from: 1, to: 5, lines: 5 },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, lines: 7 },
    review: { surah: 'النبأ', from: 1, to: 20, lines: 20 },
    lastUpdated: new Date().toISOString()
  });

  useEffect(() => {
    const loadFilteredData = () => {
      const savedStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
      const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

      const teacherCircles = savedCircles
        .filter((c: any) => c.teacher === teacherName)
        .map((c: any) => c.name);

      const filtered = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
      setStudents(filtered);
    };

    loadFilteredData();
    window.addEventListener('storage', loadFilteredData);
    return () => window.removeEventListener('storage', loadFilteredData);
  }, [teacherName]);

  const openPlanModal = (student: any) => {
    setSelectedStudent(student);
    if (student.plan) {
      setPlanForm(student.plan);
    } else {
      setPlanForm({
        hifdh: { surah: 'الفاتحة', from: 1, to: 7, lines: 7 },
        tathbeet: { surah: 'النبأ', from: 1, to: 5, lines: 5 },
        review: { surah: 'البقرة', from: 1, to: 10, lines: 10 },
        lastUpdated: new Date().toISOString()
      });
    }
    setShowPlanModal(true);
  };

  const savePlan = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => 
      s.id === selectedStudent.id ? { ...s, plan: { ...planForm, lastUpdated: new Date().toISOString() } } : s
    );
    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowPlanModal(false);
    alert(`تم بنجاح وضع الخطة الدراسية للطالب: ${selectedStudent.name}`);
  };

  const renderPlanSection = (type: 'hifdh' | 'tathbeet' | 'review', title: string, icon: string, color: string) => (
    <div className={`p-6 bg-white rounded-[32px] border-2 border-slate-100 hover:border-${color}-200 transition-all group`}>
      <div className="flex items-center justify-between mb-5">
        <div className="flex items-center gap-3">
          <span className={`w-10 h-10 rounded-xl bg-${color}-50 text-${color}-600 flex items-center justify-center text-xl shadow-sm`}>{icon}</span>
          <h4 className="font-black text-slate-800 text-sm uppercase tracking-tight">{title}</h4>
        </div>
        <span className={`text-[9px] font-black bg-slate-50 text-slate-400 px-3 py-1 rounded-full uppercase`}>اليومي</span>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div>
          <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest text-right mr-1">السورة</label>
          <select 
            className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold transition-all"
            value={planForm[type].surah}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], surah: e.target.value}})}
          >
            {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
          </select>
        </div>
        <div className="grid grid-cols-2 gap-3 col-span-2">
          <div>
            <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest text-right mr-1">من آية</label>
            <input 
              type="number" 
              className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold text-center"
              value={planForm[type].from}
              onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], from: parseInt(e.target.value)}})}
            />
          </div>
          <div>
            <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest text-right mr-1">إلى آية</label>
            <input 
              type="number" 
              className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-bold text-center"
              value={planForm[type].to}
              onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], to: parseInt(e.target.value)}})}
            />
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="bg-white p-10 rounded-[48px] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 quran-font">متابعة الخطط الدراسية</h2>
          <p className="text-slate-500 font-medium mt-1">قم بتخصيص ورد الحفظ والمراجعة لكل طالب بناءً على مستواه</p>
        </div>
        <div className="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center text-3xl shadow-inner border border-emerald-100">📋</div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {students.length > 0 ? students.map((s) => (
          <div key={s.id} className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 hover:border-emerald-200 transition-all group flex flex-col">
            <div className="flex items-center gap-4 mb-6">
              <div className="w-14 h-14 bg-slate-50 text-emerald-700 rounded-2xl flex items-center justify-center text-xl font-black shadow-inner group-hover:bg-emerald-600 group-hover:text-white transition-all">
                {s.name.charAt(0)}
              </div>
              <div className="flex-1 overflow-hidden">
                <h3 className="font-black text-slate-800 truncate">{s.name}</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{s.circle}</p>
              </div>
            </div>

            <div className="space-y-3 mb-8">
              <div className="flex justify-between items-center px-4 py-3 bg-slate-50 rounded-2xl">
                <span className="text-[10px] font-black text-slate-400 uppercase">حالة الورد</span>
                <span className={`text-[10px] font-black ${s.plan ? 'text-emerald-600' : 'text-amber-500'}`}>
                  {s.plan ? '✅ تم وضع الخطة' : '⚠️ بانتظار الخطة'}
                </span>
              </div>
              {s.plan && (
                <div className="text-[10px] font-bold text-slate-400 px-4">
                  آخر تحديث: {new Date(s.plan.lastUpdated).toLocaleDateString('ar-SA')}
                </div>
              )}
            </div>

            <button 
              onClick={() => openPlanModal(s)}
              className="mt-auto w-full py-4 bg-emerald-600 text-white rounded-[20px] text-xs font-black shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <span>📅</span> {s.plan ? 'تحديث الخطة الدراسية' : 'إعداد خطة جديدة'}
            </button>
          </div>
        )) : (
          <div className="col-span-full py-24 text-center bg-white rounded-[48px] border-2 border-dashed border-slate-100">
            <p className="text-slate-400 font-black text-xl">لا يوجد طلاب نشطين في حلقاتك</p>
            <p className="text-sm text-slate-400 mt-2">بإمكانك البدء بمجرد تسجيل طلاب جدد في الحلقة</p>
          </div>
        )}
      </div>

      {showPlanModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-[#F8FAFB] w-full max-w-3xl rounded-[56px] shadow-2xl animate-scaleIn overflow-hidden max-h-[92vh] flex flex-col border border-white/20">
            <div className="p-10 border-b bg-white flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 quran-font">تخصيص الخطة الدراسية</h3>
                <p className="text-sm text-slate-400 font-bold mt-1">تحديد المهام اليومية للطالب: {selectedStudent?.name}</p>
              </div>
              <button onClick={() => setShowPlanModal(false)} className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 rounded-full hover:bg-red-50 hover:text-red-500 transition-all font-bold">✕</button>
            </div>

            <div className="p-10 space-y-6 overflow-y-auto scrollbar-hide">
              {renderPlanSection('hifdh', 'الحفظ الجديد (الورد اليومي)', '✨', 'emerald')}
              {renderPlanSection('tathbeet', 'التثبيت (المراجعة القريبة)', '📌', 'blue')}
              {renderPlanSection('review', 'المراجعة الكبرى (الماضي القريب)', '🔄', 'purple')}
