          />
        </div>
        <div>
          <label className={labelClass}>إلى آية</label>
          <input 
            type="number" 
            className={inputClass} 
            value={studentForm.plan[type].to}
            onChange={(e) => updatePlanItem(type, 'to', parseInt(e.target.value))}
          />
        </div>
      </div>
    </div>
  );

  return (
