                      <option value="خريج">خريج</option>
                    </select>
                  </div>
                </div>
              </div>

              {/* قسم الخطة الدراسية (منهجية خليل) */}
              <div className="space-y-6 pt-6 border-t border-slate-100">
                <h4 className="text-sm font-black text-blue-800 border-r-4 border-blue-500 pr-3">الخطة الدراسية (منهجية خليل)</h4>
                <div className="space-y-6">
                  {renderPlanSection('hifdh', 'حفظ جديد (الورد اليومي)', 'emerald')}
                  {renderPlanSection('tathbeet', 'مراجعة قريبة (صغرى)', 'blue')}
                  {renderPlanSection('review', 'مراجعة بعيدة (كبرى)', 'purple')}
                </div>
              </div>
            </form>

            <div className="p-8 bg-white border-t flex gap-4 shrink-0">
              <button type="submit" onClick={handleSaveStudent} className="flex-1 bg-emerald-600 text-white py-5 rounded-[24px] font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95">
                {editingId ? 'حفظ التعديلات' : 'تسجيل الطالب واعتماد الخطة'}
              </button>
              <button type="button" onClick={() => setShowAddModal(false)} className="px-12 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-bold hover:bg-slate-200 transition-all">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

