import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

interface TeacherStudentsProps {
  teacherName?: string;
}

const TeacherStudents: React.FC<TeacherStudentsProps> = ({ teacherName }) => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showPlanModal, setShowPlanModal] = useState(false);

  const [planForm, setPlanForm] = useState<StudyPlan>({
    hifdh: { surah: 'البقرة', from: 1, to: 5, lines: 0 },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, lines: 0 },
    review: { surah: 'النبأ', from: 1, to: 20, lines: 0 },
    lastUpdated: new Date().toISOString()
  });

  useEffect(() => {
    const loadFilteredData = () => {
      const savedStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
      const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

      const teacherCircles = savedCircles
        .filter((c: any) => c.teacher === teacherName)
        .map((c: any) => c.name);

      const filtered = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
      setStudents(filtered);
    };

    loadFilteredData();
    window.addEventListener('storage', loadFilteredData);
    return () => window.removeEventListener('storage', loadFilteredData);
  }, [teacherName]);

  const openPlanModal = (student: any) => {
    setSelectedStudent(student);
    if (student.plan) {
      setPlanForm(student.plan);
    } else {
      setPlanForm({
        hifdh: { surah: 'البقرة', from: 1, to: 10, lines: 0 },
        tathbeet: { surah: 'النبأ', from: 1, to: 5, lines: 0 },
        review: { surah: 'الملك', from: 1, to: 30, lines: 0 },
        lastUpdated: new Date().toISOString()
      });
    }
    setShowPlanModal(true);
  };

  const handleSavePlan = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => 
      s.id === selectedStudent.id ? { ...s, plan: { ...planForm, lastUpdated: new Date().toISOString() } } : s
    );
    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowPlanModal(false);
    alert(`تم بنجاح تحديث الخطة الدراسية للطالب: ${selectedStudent.name}`);
  };

  const renderPlanField = (type: 'hifdh' | 'tathbeet' | 'review', label: string, icon: string, color: string) => (
    <div className={`p-8 bg-white rounded-[40px] border-2 border-slate-50 hover:border-${color}-200 transition-all group`}>
      <div className="flex items-center gap-4 mb-6">
        <div className={`w-12 h-12 bg-${color}-50 text-${color}-600 rounded-2xl flex items-center justify-center text-2xl shadow-inner`}>
          {icon}
        </div>
        <h4 className="text-lg font-black text-slate-800">{label}</h4>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">اسم السورة</label>
          <select 
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            value={planForm[type].surah}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], surah: e.target.value}})}
          >
            {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
          </select>
        </div>

        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">من آية</label>
          <input 
            type="number"
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold text-center outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            value={planForm[type].from}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], from: parseInt(e.target.value) || 0}})}
          />
        </div>

        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">إلى آية</label>
          <input 
            type="number"
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold text-center outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            value={planForm[type].to}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], to: parseInt(e.target.value) || 0}})}
          />
        </div>

        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">عدد الأسطر</label>
          <input 
            type="number"
            className="w-full px-5 py-4 bg-emerald-50/20 border-emerald-100 text-emerald-800 rounded-2xl text-sm font-black text-center outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            value={planForm[type].lines}
            onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], lines: parseInt(e.target.value) || 0}})}
          />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="bg-white p-10 rounded-[48px] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 quran-font">منهجية منصة خليل</h2>
          <p className="text-slate-500 font-medium mt-1">تخصيص المسارات الثلاثة: السورة، الآيات، وعدد الأسطر</p>
        </div>
        <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center text-4xl shadow-inner border border-emerald-100">📋</div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {students.length > 0 ? students.map((s) => (
          <div key={s.id} className="bg-white p-8 rounded-[48px] shadow-sm border border-slate-100 hover:border-emerald-200 transition-all group flex flex-col">
            <div className="flex items-center gap-5 mb-8">
              <div className="w-16 h-16 bg-slate-50 text-emerald-700 rounded-2xl flex items-center justify-center text-2xl font-black shadow-inner group-hover:bg-emerald-600 group-hover:text-white transition-all">
                {s.name.charAt(0)}
              </div>
              <div className="flex-1 overflow-hidden">
                <h3 className="text-xl font-black text-slate-800 truncate">{s.name}</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{s.circle}</p>
              </div>
            </div>

            <div className="space-y-4 mb-8">
              <div className="flex justify-between items-center px-5 py-4 bg-slate-50 rounded-2xl">
                <span className="text-[10px] font-black text-slate-400 uppercase">الخطة الدراسية</span>
                <span className={`text-[10px] font-black ${s.plan ? 'text-emerald-600' : 'text-amber-500'}`}>
                  {s.plan ? '✅ معتمدة' : '⚠️ بانتظار الخطة'}
                </span>
              </div>
            </div>

            <button 
              onClick={() => openPlanModal(s)}
              className="mt-auto w-full py-5 bg-emerald-600 text-white rounded-[24px] text-sm font-black shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              <span>⚙️</span> تعديل الورد اليومي
            </button>
          </div>
        )) : (
          <div className="col-span-full py-32 text-center bg-white rounded-[56px] border-2 border-dashed border-slate-100">
            <div className="text-6xl mb-6 opacity-20">📜</div>
            <p className="text-slate-400 font-black text-xl">لا يوجد طلاب نشطين في حلقاتك</p>
          </div>
        )}
      </div>

      {showPlanModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-[#F8FAFB] w-full max-w-4xl rounded-[64px] shadow-2xl animate-scaleIn overflow-hidden max-h-[95vh] flex flex-col border border-white/20">
            <div className="p-10 border-b bg-white flex justify-between items-center">
              <div className="text-right">
                <h3 className="text-2xl font-black text-slate-800 quran-font">تخصيص الورد والأسطر</h3>
                <p className="text-sm text-slate-400 font-bold mt-1">تطبيق المنهجية الثلاثية للطالب: {selectedStudent?.name}</p>
              </div>
              <button 
                onClick={() => setShowPlanModal(false)} 
                className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 rounded-full hover:bg-red-50 hover:text-red-500 transition-all font-bold"
              >
                ✕
              </button>
            </div>

            <div className="p-10 space-y-8 overflow-y-auto scrollbar-hide">
              {renderPlanField('hifdh', 'حفظ جديد (المسار الأول)', '✨', 'emerald')}
              {renderPlanField('tathbeet', 'مراجعة قريبة - صغرى (المسار الثاني)', '📌', 'blue')}
              {renderPlanField('review', 'مراجعة بعيدة - كبرى (المسار الثالث)', '🔄', 'purple')}
            </div>

            <div className="p-10 bg-white border-t flex gap-6">
              <button 
                onClick={handleSavePlan}
                className="flex-1 bg-emerald-600 text-white py-6 rounded-[32px] font-black shadow-2xl shadow-emerald-200 hover:bg-emerald-700 transition-all active:scale-95"
              >
                حفظ الخطة والأسطر
              </button>
              <button 
                onClick={() => setShowPlanModal(false)}
                className="px-12 py-6 bg-slate-100 text-slate-500 rounded-[32px] font-black hover:bg-slate-200 transition-all"
              >
                إلغاء
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

