          <div className="bg-white w-full max-w-2xl rounded-[48px] shadow-2xl overflow-hidden animate-scaleIn border border-white/20">
            <div className="p-8 bg-emerald-900 text-white flex justify-between items-center text-right">
              <div>
                <h3 className="text-xl font-black quran-font">رصد تقييم التسميع: {selectedStudent?.name}</h3>
                <p className="text-xs text-emerald-200 font-bold mt-1">منهجية منصة خليل • التحصيل الأكاديمي</p>
              </div>
              <button 
                onClick={() => setShowRecitationModal(false)} 
