            <div className="p-10 space-y-6 max-h-[70vh] overflow-y-auto scrollbar-hide">
              {[
                { id: 'hifdh', title: 'المسار الأول: حفظ جديد', color: 'emerald', icon: '✨' },
                { id: 'tathbeet', title: 'المسار الثاني: مراجعة قريبة (صغرى)', color: 'blue', icon: '📌' },
                { id: 'review', title: 'المسار الثالث: مراجعة بعيدة (كبرى)', color: 'purple', icon: '🔄' }
              ].map((section: any) => (
                <div key={section.id} className="p-6 bg-slate-50 rounded-[32px] border-2 border-slate-100 hover:border-emerald-100 transition-all">
                  <div className="flex items-center gap-3 mb-4">
