                          >
                            {g === 'يعاد' ? '🔄' : g}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="p-8 bg-slate-50 border-t flex gap-4">
              <button 
                onClick={saveRecitation} 
                className="flex-1 py-5 bg-emerald-600 text-white rounded-[24px] font-black shadow-2xl shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3"
