                <h4 className="text-sm font-black text-emerald-800 border-r-4 border-emerald-500 pr-3">البيانات الأساسية</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className={labelClass}>الاسم الكامل</label>
                    <input required type="text" className={inputClass} value={studentForm.name} onChange={(e) => setStudentForm({...studentForm, name: e.target.value})} placeholder="أدخل اسم الطالب الكامل" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className={labelClass}>رقم الهوية</label>
                      <input required type="text" className={inputClass} value={studentForm.idNumber} onChange={(e) => setStudentForm({...studentForm, idNumber: e.target.value})} />
                    </div>
                    <div>
                      <label className={labelClass}>تاريخ الميلاد</label>
                      <input required type="date" className={inputClass} value={studentForm.birthDate} onChange={(e) => setStudentForm({...studentForm, birthDate: e.target.value})} />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className={labelClass}>رقم ولي الأمر</label>
                      <input required type="tel" className={inputClass} value={studentForm.parentPhone} onChange={(e) => setStudentForm({...studentForm, parentPhone: e.target.value})} placeholder="05xxxxxxxx" />
                    </div>
                    <div>
                      <label className={labelClass}>الحلقة</label>
                      <select required className={inputClass} value={studentForm.circle} onChange={(e) => setStudentForm({...studentForm, circle: e.target.value})}>
