              {renderPlanField('tathbeet', 'مراجعة قريبة (المسار الثاني)', '📌', 'blue')}
              {renderPlanField('review', 'مراجعة بعيدة (المسار الثالث)', '🔄', 'purple')}
            </div>

            <div className="p-10 bg-white border-t flex gap-6">
              <button 
                onClick={handleSavePlan}
                className="flex-1 bg-emerald-600 text-white py-6 rounded-[32px] font-black shadow-2xl shadow-emerald-200 hover:bg-emerald-700 transition-all active:scale-95"
              >
                حفظ المنهج والأسطر
              </button>
              <button 
                onClick={() => setShowPlanModal(false)}
                className="px-12 py-6 bg-slate-100 text-slate-500 rounded-[32px] font-black hover:bg-slate-200 transition-all"
              >
                إلغاء
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

