import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

const ManagerStudents: React.FC = () => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [circles, setCircles] = useState<any[]>([]);

  const initialPlanState: StudyPlan = {
    hifdh: { surah: 'البقرة', from: 1, to: 1, lines: 15 },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, lines: 7 },
    review: { surah: 'النبأ', from: 1, to: 40, lines: 20 },
    lastUpdated: new Date().toISOString()
  };

  const [studentForm, setStudentForm] = useState({
    name: '',
    circle: '',
    idNumber: '',
    birthDate: '',
    status: 'نشط',
    parentPhone: '',
    plan: initialPlanState
  });

  useEffect(() => {
    const loadData = () => {
      const savedStudents = localStorage.getItem('afaq_students');
      const savedCircles = localStorage.getItem('afaq_circles');

      if (savedStudents) setStudents(JSON.parse(savedStudents));
      if (savedCircles) setCircles(JSON.parse(savedCircles));
    };

    loadData();
    window.addEventListener('storage', loadData);
    return () => window.removeEventListener('storage', loadData);
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setStudentForm({ 
      name: '', 
      circle: '', 
      idNumber: '', 
      birthDate: '', 
      status: 'نشط', 
      parentPhone: '',
      plan: initialPlanState
    });
    setShowAddModal(true);
  };

  const openEditModal = (student: any) => {
    setEditingId(student.id);
    setStudentForm({
      name: student.name,
      circle: student.circle || '',
      idNumber: student.idNumber || '',
      birthDate: student.birthDate || '',
      status: student.status || 'نشط',
      parentPhone: student.parentPhone || '',
      plan: student.plan || initialPlanState
    });
    setShowAddModal(true);
  };

  const handleSaveStudent = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedStudents;

    const finalStudentData = {
      ...studentForm,
      plan: { ...studentForm.plan, lastUpdated: new Date().toISOString() }
    };

    if (editingId) {
      updatedStudents = students.map(s => 
        s.id === editingId ? { ...s, ...finalStudentData } : s
      );
    } else {
      const newStudent = {
        id: Date.now().toString(),
        ...finalStudentData,
        progress: 0,
        joinDate: new Date().toISOString().split('T')[0]
      };
      updatedStudents = [newStudent, ...students];
    }

    setStudents(updatedStudents);
    localStorage.setItem('afaq_students', JSON.stringify(updatedStudents));
    window.dispatchEvent(new Event('storage'));
    setShowAddModal(false);
  };

  const updatePlanItem = (type: keyof StudyPlan, field: string, value: any) => {
    if (type === 'lastUpdated') return;
    setStudentForm({
      ...studentForm,
      plan: {
        ...studentForm.plan,
        [type]: {
          ...(studentForm.plan[type] as any),
          [field]: value
        }
      }
    });
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1 tracking-widest uppercase";
  const inputClass = "w-full px-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all";

  const renderPlanSection = (type: 'hifdh' | 'tathbeet' | 'review', label: string, color: string) => {
    const isRange = type === 'tathbeet' || type === 'review';

    return (
      <div className={`p-6 rounded-[32px] border-2 border-slate-50 bg-slate-50/30 space-y-4`}>
        <h4 className={`text-xs font-black text-${color}-700 flex items-center gap-2`}>
          <span className={`w-2 h-2 rounded-full bg-${color}-500 animate-pulse`}></span>
          {label}
        </h4>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          <div className="md:col-span-1">
            <label className={labelClass}>السورة</label>
            <select 
              className={inputClass}
              value={studentForm.plan[type].surah}
              onChange={(e) => updatePlanItem(type, 'surah', e.target.value)}
            >
              {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
            </select>
          </div>
          <div>
            <label className={labelClass}>من آية</label>
            <input 
              type="number" 
              className={inputClass} 
              value={studentForm.plan[type].from}
              onChange={(e) => updatePlanItem(type, 'from', parseInt(e.target.value) || 0)}
            />
          </div>
          {isRange ? (
            <div>
              <label className={labelClass}>إلى آية</label>
              <input 
                type="number" 
                className={inputClass} 
                value={studentForm.plan[type].to}
                onChange={(e) => updatePlanItem(type, 'to', parseInt(e.target.value) || 0)}
              />
            </div>
          ) : (
            <div>
              <label className={labelClass}>عدد الأسطر</label>
              <input 
                type="number" 
                className={`${inputClass} bg-amber-50/30 border-amber-100 text-amber-700`} 
                value={studentForm.plan[type].lines}
                onChange={(e) => updatePlanItem(type, 'lines', parseInt(e.target.value) || 0)}
              />
            </div>
          )}
          {!isRange && <div></div>} {/* spacer for hifdh layout */}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-12 text-right">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-black text-slate-800 quran-font">شؤون الطلاب</h2>
          <p className="text-slate-500 text-sm font-medium">إدارة السجلات والخطط الدراسية لكل طالب</p>
        </div>
        <button onClick={openAddModal} className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-emerald-700 transition-all shadow-xl flex items-center gap-2 active:scale-95"><span>➕</span> تسجيل طالب جديد</button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5">اسم الطالب</th>
              <th className="px-6 py-5">رقم ولي الأمر</th>
              <th className="px-6 py-5">الحلقة</th>
              <th className="px-6 py-5">الخطة</th>
              <th className="px-8 py-5 text-left">الإدارة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {students.length > 0 ? students.map((st) => (
              <tr key={st.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center font-black">{st.name.charAt(0)}</div>
                    <div>
                      <p className="font-bold text-slate-800">{st.name}</p>
                      <p className="text-[10px] text-slate-400 font-medium">{st.idNumber}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <span className="text-xs font-bold text-slate-700">{st.parentPhone || 'غير متوفر'}</span>
                </td>
                <td className="px-6 py-5">
                  <span className="text-xs font-bold text-slate-500">{st.circle || 'غير محدد'}</span>
                </td>
                <td className="px-6 py-5">
                  <span className={`px-3 py-1 rounded-full text-[9px] font-black ${st.plan ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    {st.plan ? '✅ مفعلة' : '⚠️ غير محددة'}
                  </span>
                </td>
                <td className="px-8 py-5 text-left">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openEditModal(st)} className="p-2.5 hover:bg-blue-50 text-blue-600 rounded-xl transition-all border border-transparent hover:border-blue-100 shadow-sm flex items-center gap-2 text-xs font-bold">📝 تعديل</button>
                    <button onClick={() => { if(window.confirm('حذف؟')){setStudents(students.filter(s=>s.id!==st.id)); localStorage.setItem('afaq_students', JSON.stringify(students.filter(s=>s.id!==st.id))); window.dispatchEvent(new Event('storage')); }}} className="p-2.5 hover:bg-red-50 text-red-600 rounded-xl transition-all border border-transparent hover:border-red-100 shadow-sm flex items-center gap-2 text-xs font-bold">🗑️ حذف</button>
                  </div>
                </td>
              </tr>
            )) : (
              <tr><td colSpan={5} className="py-20 text-center text-slate-400 font-bold">لا يوجد طلاب مسجلين حالياً</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl rounded-[56px] shadow-2xl animate-scaleIn overflow-hidden max-h-[95vh] flex flex-col">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center shrink-0">
              <h3 className="text-xl font-black text-slate-800 quran-font">{editingId ? 'تعديل بيانات الطالب' : 'تسجيل طالب جديد'}</h3>
              <button onClick={() => setShowAddModal(false)} className="text-slate-400 font-bold text-xl hover:text-red-500 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSaveStudent} className="flex-1 overflow-y-auto p-10 space-y-10 scrollbar-hide">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className={labelClass}>الاسم الكامل</label>
                  <input required type="text" className={inputClass} value={studentForm.name} onChange={(e) => setStudentForm({...studentForm, name: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>رقم ولي الأمر</label>
                  <input required type="tel" className={inputClass} value={studentForm.parentPhone} onChange={(e) => setStudentForm({...studentForm, parentPhone: e.target.value})} />
                </div>
                <div>
                  <label className={labelClass}>الحلقة</label>
                  <select required className={inputClass} value={studentForm.circle} onChange={(e) => setStudentForm({...studentForm, circle: e.target.value})}>
                    <option value="">اختر الحلقة...</option>
                    {circles.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
              </div>

              <div className="space-y-6 pt-6 border-t border-slate-100">
                <h4 className="text-sm font-black text-emerald-800 border-r-4 border-emerald-500 pr-3">تخصيص المنهج الأكاديمي</h4>
                {renderPlanSection('hifdh', 'حفظ جديد (نقطة البداية + كمية)', 'emerald')}
                {renderPlanSection('tathbeet', 'تثبيت ومراجعة صغرى (نطاق آيات)', 'blue')}
                {renderPlanSection('review', 'مراجعة كبرى (نطاق آيات)', 'purple')}
              </div>
            </form>

            <div className="p-8 bg-white border-t flex gap-4 shrink-0">
              <button type="submit" onClick={handleSaveStudent} className="flex-1 bg-emerald-600 text-white py-5 rounded-[24px] font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95">حفظ البيانات والمنهج</button>
              <button type="button" onClick={() => setShowAddModal(false)} className="px-12 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-bold">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagerStudents;

import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';

interface TeacherDashboardProps {
  teacherName?: string;
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ teacherName }) => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showRecitationModal, setShowRecitationModal] = useState(false);

  const [recitationForm, setRecitationForm] = useState<any>({
    hifdh: { surah: 'النبأ', grade: '10' },
    tathbeet: { surah: 'النازعات', grade: '10' },
    review: { surah: 'النبأ', grade: '10' },
    notes: ''
  });

  useEffect(() => {
    const loadData = () => {
      const savedStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
      const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

      const teacherCircles = savedCircles
        .filter((c: any) => c.teacher === teacherName)
        .map((c: any) => c.name);

      const filteredStudents = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
      setStudents(filteredStudents);
    };

    loadData();
    window.addEventListener('storage', loadData);
    return () => window.removeEventListener('storage', loadData);
  }, [teacherName]);

  const handleAttendance = (studentId: string, status: string) => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => s.id === studentId ? { ...s, attendance: status } : s);
    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    setStudents(updatedAll.filter((s: any) => students.some(cur => cur.id === s.id)));
    window.dispatchEvent(new Event('storage'));
  };

  const openRecitation = (student: any) => {
    setSelectedStudent(student);
    setRecitationForm({
      hifdh: student.plan?.hifdh ? { ...student.plan.hifdh, grade: '10' } : { surah: 'النبأ', grade: '10' },
      tathbeet: student.plan?.tathbeet ? { ...student.plan.tathbeet, grade: '10' } : { surah: 'النازعات', grade: '10' },
      review: student.plan?.review ? { ...student.plan.review, grade: '10' } : { surah: 'النبأ', grade: '10' },
      notes: ''
    });
    setShowRecitationModal(true);
  };

  const saveRecitation = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => {
      if (s.id === selectedStudent.id) {
        return {
          ...s,
          status: 'تم التسميع',
          lastGrade: recitationForm.hifdh.grade,
          history: [...(s.history || []), { 
            date: new Date().toISOString(), 
            summary: recitationForm 
          }]
        };
      }
      return s;
    });

    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowRecitationModal(false);
  };

  const labelClass = "block text-[10px] font-black text-slate-400 mb-1.5 uppercase tracking-widest";
  const inputClass = "w-full px-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all";

  const getGradesForCategory = (categoryId: string) => {
    if (categoryId === 'hifdh' || categoryId === 'tathbeet') return ['10', '9', 'يعاد'];
    return ['10', '9', '8', 'يعاد'];
  };

  return (
    <div className="space-y-6 animate-fadeIn text-right pb-10">
      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl font-bold">👨‍🏫</div>
          <div>
            <h2 className="text-2xl font-black text-slate-800 quran-font">تحضير الطلاب وتسميعهم</h2>
            <p className="text-slate-500 text-sm font-medium">مرحباً {teacherName}، اختر حالة الطالب لفتح نافذة التقييم</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-right text-sm">
          <thead className="bg-slate-50 border-b">
            <tr className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
              <th className="px-8 py-5 text-right">الطالب</th>
              <th className="px-6 py-5 text-right">الحلقة</th>
              <th className="px-6 py-5 text-center">حالة التحضير اليومي</th>
              <th className="px-8 py-5 text-left">التسميع</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {students.length > 0 ? students.map((student) => (
              <tr key={student.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-8 py-5 text-right">
                  <div className="font-bold text-slate-700">{student.name}</div>
                  <div className="text-[9px] text-slate-400 font-bold uppercase">ID: {student.idNumber}</div>
                </td>
                <td className="px-6 py-5 text-right">
                   <span className="text-xs text-slate-500 font-bold bg-slate-100 px-3 py-1 rounded-lg">{student.circle}</span>
                </td>
                <td className="px-6 py-5">
                   <div className="flex justify-center gap-1.5">
                     {[
                       { key: 'حاضر', icon: '✅', color: 'emerald' },
                       { key: 'غائب', icon: '❌', color: 'red' },
                       { key: 'متأخر', icon: '⏳', color: 'amber' },
                       { key: 'مستأذن', icon: '📝', color: 'blue' }
                     ].map((btn) => (
                       <button
                         key={btn.key}
                         onClick={() => handleAttendance(student.id, btn.key)}
                         className={`w-10 h-10 flex items-center justify-center rounded-xl text-sm transition-all border shadow-sm ${
                           student.attendance === btn.key 
                           ? `bg-${btn.color}-600 text-white border-${btn.color}-600 scale-110 shadow-lg` 
                           : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'
                         }`}
                       >
                         {btn.icon}
                       </button>
                     ))}
                   </div>
                </td>
                <td className="px-8 py-5 text-left">
                  {student.attendance === 'حاضر' ? (
                    <button 
                      onClick={() => openRecitation(student)} 
                      className="bg-emerald-600 text-white px-6 py-3 rounded-2xl text-[10px] font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95 animate-scaleIn"
                    >
                      🎙️ رصد التسميع
                    </button>
                  ) : (
                    <span className="text-[10px] font-bold text-slate-300 italic px-4">بانتظار التحضير</span>
                  )}
                </td>
              </tr>
            )) : (
              <tr><td colSpan={4} className="py-24 text-center text-slate-400 font-black">لا يوجد طلاب في حلقاتك حالياً</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {showRecitationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[48px] shadow-2xl overflow-hidden animate-scaleIn">
            <div className="p-8 bg-emerald-900 text-white flex justify-between items-center text-right">
              <div>
                <h3 className="text-xl font-black quran-font">تقييم تسميع: {selectedStudent?.name}</h3>
                <p className="text-xs text-emerald-200 font-bold mt-1">منهجية آفاق • الورد اليومي</p>
              </div>
              <button onClick={() => setShowRecitationModal(false)} className="text-2xl">✕</button>
            </div>

            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              {[
                { id: 'hifdh', title: 'حفظ جديد (نقطة البداية)', color: 'emerald', icon: '✨' },
                { id: 'tathbeet', title: 'تثبيت ومراجعة صغرى (نطاق)', color: 'blue', icon: '📌' },
                { id: 'review', title: 'مراجعة كبرى (نطاق)', color: 'purple', icon: '🔄' }
              ].map((section: any) => {
                const isRange = section.id !== 'hifdh';
                const planData = selectedStudent?.plan?.[section.id];

                return (
                  <div key={section.id} className="p-5 bg-slate-50 rounded-[32px] border-2 border-slate-100">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-3">
                        <span className={`text-lg`}>{section.icon}</span>
                        <h4 className="text-sm font-black text-slate-800">{section.title}</h4>
                      </div>
                      {planData && (
                        <div className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg">
                          {planData.surah} • {planData.from} {isRange ? `إلى ${planData.to}` : `(الأسطر: ${planData.lines})`}
                        </div>
                      )}
                    </div>

                    <div className="flex flex-col md:flex-row gap-4 items-end">
                      <div className="flex-1 w-full">
                        <label className={labelClass}>تغيير السورة (اختياري)</label>
                        <select className={inputClass} value={recitationForm[section.id].surah} onChange={(e) => setRecitationForm({...recitationForm, [section.id]: {...recitationForm[section.id], surah: e.target.value}})}>
                          {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                        </select>
                      </div>

                      <div className="space-y-2">
                        <label className={labelClass}>الدرجة</label>
                        <div className="flex gap-2">
                          {getGradesForCategory(section.id).map(g => (
                            <button 
                              key={g} 
                              onClick={() => setRecitationForm({...recitationForm, [section.id]: {...recitationForm[section.id], grade: g}})}
                              className={`w-12 h-12 rounded-xl text-[11px] font-black border transition-all flex items-center justify-center ${
                                recitationForm[section.id].grade === g 
                                ? `bg-emerald-600 text-white border-emerald-600 shadow-lg` 
                                : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'
                              }`}
                            >
                              {g === 'يعاد' ? '🔄' : g}
                            </button>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="p-8 bg-slate-50 border-t flex gap-4">
              <button onClick={saveRecitation} className="flex-1 py-5 bg-emerald-600 text-white rounded-[24px] font-black shadow-lg">حفظ واعتماد الدرجات</button>
              <button onClick={() => setShowRecitationModal(false)} className="px-10 py-5 bg-white text-slate-500 rounded-[24px] font-black border border-slate-200">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useEffect } from 'react';
import { SURAHS } from '../constants';
import { StudyPlan } from '../types';

interface TeacherStudentsProps {
  teacherName?: string;
}

const TeacherStudents: React.FC<TeacherStudentsProps> = ({ teacherName }) => {
  const [students, setStudents] = useState<any[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [showPlanModal, setShowPlanModal] = useState(false);

  const [planForm, setPlanForm] = useState<StudyPlan>({
    hifdh: { surah: 'البقرة', from: 1, to: 1, lines: 15 },
    tathbeet: { surah: 'الفاتحة', from: 1, to: 7, lines: 7 },
    review: { surah: 'النبأ', from: 1, to: 40, lines: 20 },
    lastUpdated: new Date().toISOString()
  });

  useEffect(() => {
    const loadFilteredData = () => {
      const savedStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
      const savedCircles = JSON.parse(localStorage.getItem('afaq_circles') || '[]');

      const teacherCircles = savedCircles
        .filter((c: any) => c.teacher === teacherName)
        .map((c: any) => c.name);

      const filtered = savedStudents.filter((s: any) => teacherCircles.includes(s.circle));
      setStudents(filtered);
    };

    loadFilteredData();
    window.addEventListener('storage', loadFilteredData);
    return () => window.removeEventListener('storage', loadFilteredData);
  }, [teacherName]);

  const openPlanModal = (student: any) => {
    setSelectedStudent(student);
    if (student.plan) {
      setPlanForm(student.plan);
    } else {
      setPlanForm({
        hifdh: { surah: 'البقرة', from: 1, to: 1, lines: 15 },
        tathbeet: { surah: 'النبأ', from: 1, to: 30, lines: 5 },
        review: { surah: 'الملك', from: 1, to: 30, lines: 30 },
        lastUpdated: new Date().toISOString()
      });
    }
    setShowPlanModal(true);
  };

  const handleSavePlan = () => {
    const allStudents = JSON.parse(localStorage.getItem('afaq_students') || '[]');
    const updatedAll = allStudents.map((s: any) => 
      s.id === selectedStudent.id ? { ...s, plan: { ...planForm, lastUpdated: new Date().toISOString() } } : s
    );
    localStorage.setItem('afaq_students', JSON.stringify(updatedAll));
    window.dispatchEvent(new Event('storage'));
    setShowPlanModal(false);
    alert(`تم بنجاح تحديث المنهج للطالب: ${selectedStudent.name}`);
  };

  const renderPlanField = (type: 'hifdh' | 'tathbeet' | 'review', label: string, icon: string, color: string) => {
    const isRange = type !== 'hifdh';

    return (
      <div className={`p-8 bg-white rounded-[40px] border-2 border-slate-50 hover:border-${color}-200 transition-all group`}>
        <div className="flex items-center gap-4 mb-6">
          <div className={`w-12 h-12 bg-${color}-50 text-${color}-600 rounded-2xl flex items-center justify-center text-2xl shadow-inner`}>
            {icon}
          </div>
          <h4 className="text-lg font-black text-slate-800">{label}</h4>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="md:col-span-1">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">السورة</label>
            <select 
              className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
              value={planForm[type].surah}
              onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], surah: e.target.value}})}
            >
              {SURAHS.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
            </select>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">من آية</label>
            <input 
              type="number"
              className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-center"
              value={planForm[type].from}
              onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], from: parseInt(e.target.value) || 0}})}
            />
          </div>

          {isRange ? (
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">إلى آية</label>
              <input 
                type="number"
                className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-center"
                value={planForm[type].to}
                onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], to: parseInt(e.target.value) || 0}})}
              />
            </div>
          ) : (
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">الكمية (أسطر)</label>
              <input 
                type="number"
                className="w-full px-4 py-3 bg-emerald-50 text-emerald-800 border border-emerald-100 rounded-xl text-xs font-black text-center"
                value={planForm[type].lines}
                onChange={(e) => setPlanForm({...planForm, [type]: {...planForm[type], lines: parseInt(e.target.value) || 0}})}
              />
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fadeIn text-right">
      <div className="bg-white p-10 rounded-[48px] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 quran-font">تخصيص المنهج الأكاديمي</h2>
          <p className="text-slate-500 font-medium mt-1">تحديد نطاق الآيات للمراجعة والكمية للحفظ</p>
        </div>
        <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center text-4xl shadow-inner border border-emerald-100">📋</div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {students.length > 0 ? students.map((s) => (
          <div key={s.id} className="bg-white p-8 rounded-[48px] shadow-sm border border-slate-100 hover:border-emerald-200 transition-all group flex flex-col h-full">
            <div className="flex items-center gap-5 mb-8">
              <div className="w-16 h-16 bg-slate-50 text-emerald-700 rounded-2xl flex items-center justify-center text-2xl font-black shadow-inner">
                {s.name.charAt(0)}
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-800 truncate">{s.name}</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase">{s.circle}</p>
              </div>
            </div>
            <button onClick={() => openPlanModal(s)} className="mt-auto w-full py-5 bg-emerald-600 text-white rounded-[24px] text-sm font-black shadow-xl hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3">
              <span>⚙️</span> تعديل المنهج الدراسي
            </button>
          </div>
        )) : (
          <div className="col-span-full py-32 text-center bg-white rounded-[56px] border border-dashed border-slate-100 text-slate-400 font-black">لا يوجد طلاب نشطين</div>
        )}
      </div>

      {showPlanModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-[#F8FAFB] w-full max-w-4xl rounded-[64px] shadow-2xl animate-scaleIn overflow-hidden max-h-[95vh] flex flex-col">
            <div className="p-10 border-b bg-white flex justify-between items-center text-right">
              <div>
                <h3 className="text-2xl font-black text-slate-800 quran-font">تحديد منهج الطالب</h3>
                <p className="text-sm text-slate-400 font-bold mt-1">ضبط نطاقات الحفظ والمراجعة للطالب: {selectedStudent?.name}</p>
              </div>
              <button onClick={() => setShowPlanModal(false)} className="text-2xl">✕</button>
            </div>

            <div className="p-10 space-y-8 overflow-y-auto scrollbar-hide text-right">
              {renderPlanField('hifdh', 'حفظ جديد (نقطة البداية + أسطر)', '✨', 'emerald')}
              {renderPlanField('tathbeet', 'تثبيت ومراجعة صغرى (نطاق)', '📌', 'blue')}
              {renderPlanField('review', 'مراجعة كبرى (نطاق)', 'purple')}
            </div>

            <div className="p-10 bg-white border-t flex gap-6">
              <button onClick={handleSavePlan} className="flex-1 bg-emerald-600 text-white py-6 rounded-[32px] font-black shadow-2xl hover:bg-emerald-700 transition-all active:scale-95">حفظ واعتماد المنهج</button>
              <button onClick={() => setShowPlanModal(false)} className="px-12 py-6 bg-slate-100 text-slate-500 rounded-[32px] font-black hover:bg-slate-200 transition-all">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TeacherStudents;

import React, { useState, useEffect } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
