const chartData = [
  { name: 'الأحد', verses: 12, color: '#10b981' },
  { name: 'الإثنين', verses: 25, color: '#3b82f6' },
  { name: 'الثلاثاء', verses: 18, color: '#f59e0b' },
  { name: 'الأربعاء', verses: 30, color: '#8b5cf6' },
